/* ── js/subscriptions.js ── */
// ══════════════════════════════════════════════════
// SUBSCRIPTIONS.JS — Assinaturas
// ══════════════════════════════════════════════════

// ── Calcula a parte do dono da assinatura (minha parcela mensal) ──
function calcMySubPart(s) {
  const owner = s.owner || 'mine';
  if (owner === 'mine') return s.amount;
  if (owner === 'other') return 0;
  // split
  const count = (s.splitPeople || []).length + 1;
  if (s.splitValues && s.splitValues.length) {
    return s.amount - s.splitValues.reduce((a, v) => a + (v || 0), 0);
  }
  return s.amount / count;
}

function setSubOwner(o) {
  S.subOwner = o;
  document.getElementById('sOwnerMine').classList.toggle('active', o === 'mine');
  document.getElementById('sOwnerOther').classList.toggle('active', o === 'other');
  document.getElementById('sOwnerSplit').classList.toggle('active', o === 'split');
  document.getElementById('sOtherGroup').style.display = o === 'other' ? 'block' : 'none';
  document.getElementById('sSplitGroup').style.display = o === 'split' ? 'block' : 'none';
  if (o === 'split') {
    if (!S.subSplitPeople || !S.subSplitPeople.length) S.subSplitPeople = [''];
    renderSubSplitUI();
  }
  updateSubSplitHint();
}

function setSubSplitType(t) {
  S.subSplitType = t;
  document.getElementById('sSplitEqual').classList.toggle('active', t === 'equal');
  document.getElementById('sSplitFixed').classList.toggle('active', t === 'fixed');
  renderSubSplitUI();
  updateSubSplitHint();
}

function addSubSplitPerson() {
  if (!S.subSplitPeople) S.subSplitPeople = [];
  S.subSplitPeople.push('');
  renderSubSplitUI();
  updateSubSplitHint();
}

function renderSubSplitUI() {
  const wrap = document.getElementById('sSplitPeopleWrap');
  const fixedWrap = document.getElementById('sFixedValuesWrap');
  if (!wrap) return;
  const people = S.subSplitPeople || [''];
  const known = getAllPeople();

  wrap.innerHTML = people.map((p, i) => `
    <div style="display:flex;gap:6px;margin-bottom:6px;align-items:center">
      <input type="text" placeholder="Nome da pessoa ${i + 1}" value="${(p || '').replace(/"/g, '&quot;')}"
        data-sub-person-idx="${i}" style="flex:1">
      ${people.length > 1 ? `<button type="button" data-sub-person-remove="${i}"
        style="background:none;border:none;color:var(--text3);cursor:pointer;font-size:16px;padding:0 4px;flex-shrink:0">×</button>` : ''}
    </div>`).join('') +
    `<button type="button" onclick="addSubSplitPerson()" class="btn btn-ghost btn-sm" style="margin-top:2px">+ Pessoa</button>` +
    (known.length ? `<div style="font-size:11px;color:var(--text3);margin-top:6px;margin-bottom:3px">Cadastradas:</div>
      <div class="chips" style="margin-bottom:4px" id="subKnownChips"></div>` : '');

  wrap.querySelectorAll('input[data-sub-person-idx]').forEach(inp => {
    const idx = parseInt(inp.dataset.subPersonIdx);
    inp.addEventListener('input', () => { S.subSplitPeople[idx] = inp.value; updateSubSplitHint(); });
  });
  wrap.querySelectorAll('button[data-sub-person-remove]').forEach(btn => {
    const idx = parseInt(btn.dataset.subPersonRemove);
    btn.addEventListener('click', () => {
      S.subSplitPeople.splice(idx, 1);
      if (S.subSplitValues) S.subSplitValues.splice(idx, 1);
      renderSubSplitUI(); updateSubSplitHint();
    });
  });
  const chipsDiv = document.getElementById('subKnownChips');
  if (chipsDiv) {
    known.forEach(p => {
      const chip = document.createElement('div');
      chip.className = 'chip'; chip.textContent = p;
      chip.addEventListener('click', () => {
        const emptyIdx = (S.subSplitPeople || []).findIndex(x => !x);
        if (emptyIdx >= 0) S.subSplitPeople[emptyIdx] = p;
        else S.subSplitPeople.push(p);
        renderSubSplitUI(); updateSubSplitHint();
      });
      chipsDiv.appendChild(chip);
    });
  }

  if (!fixedWrap) return;
  if (S.subSplitType === 'fixed') {
    fixedWrap.style.display = 'block';
    if (!S.subSplitValues) S.subSplitValues = people.map(() => 0);
    while (S.subSplitValues.length < people.length) S.subSplitValues.push(0);
    S.subSplitValues = S.subSplitValues.slice(0, people.length);
    fixedWrap.innerHTML = `<div style="font-size:11px;color:var(--text3);margin-bottom:6px">Valor que cada pessoa paga (R$):</div>` +
      people.map((p, i) => `
        <div style="display:flex;gap:8px;align-items:center;margin-bottom:6px">
          <span style="flex:1;font-size:13px">${p || 'Pessoa ' + (i + 1)}</span>
          <input type="number" step="0.01" placeholder="0,00" value="${S.subSplitValues[i] || ''}"
            data-sub-fixed-idx="${i}" style="width:100px">
        </div>`).join('');
    fixedWrap.querySelectorAll('input[data-sub-fixed-idx]').forEach(inp => {
      const idx = parseInt(inp.dataset.subFixedIdx);
      inp.addEventListener('input', () => {
        if (!S.subSplitValues) S.subSplitValues = [];
        S.subSplitValues[idx] = parseFloat(inp.value) || 0;
        updateSubSplitHint();
      });
    });
  } else {
    fixedWrap.style.display = 'none';
  }
}

function updateSubSplitHint() {
  const hint = document.getElementById('sSplitHint');
  if (!hint || S.subOwner !== 'split') return;
  const amt = parseFloat(document.getElementById('sAmt')?.value) || 0;
  if (amt <= 0) { hint.textContent = ''; return; }
  const people = S.subSplitPeople || [];
  const count = people.length + 1;
  if (S.subSplitType === 'fixed') {
    const vals = S.subSplitValues || [];
    const othersTotal = vals.reduce((s, v) => s + (v || 0), 0);
    const myPart = amt - othersTotal;
    hint.innerHTML = `<span style="color:var(--accent)">Eu: R$ ${fmt(myPart)}</span> · ` +
      people.map((p, i) => `<span style="color:var(--blue)">${p || 'Pessoa '+(i+1)}: R$ ${fmt(vals[i] || 0)}</span>`).join(' · ');
  } else {
    const each = amt / count;
    hint.innerHTML = `<span style="color:var(--accent)">Eu: R$ ${fmt(each)}</span> · ` +
      people.map(p => `<span style="color:var(--blue)">${p || '?'}: R$ ${fmt(each)}</span>`).join(' · ');
  }
}

function calcAnualTotal(subs) {
  return subs.reduce((t, s) => {
    if (s.cycle === 'mensal')   return t + s.amount * 12;
    if (s.cycle === 'anual')    return t + s.amount;
    if (s.cycle === 'semanal')  return t + s.amount * 52;
    return t + s.amount * 12;
  }, 0);
}

let _subProjFilter = 'all';

function toggleSubProjection() {
  const el = document.getElementById('subProjection');
  if (!el) return;
  const hidden = el.style.display === 'none';
  el.style.display = hidden ? 'block' : 'none';
}

function setSubProjFilter(f) {
  _subProjFilter = f;
  renderSubs();
  // Reabre a projeção após re-render
  const el = document.getElementById('subProjection');
  if (el) el.style.display = 'block';
}

function openSubM(editId = null) {
  clr('sName', 'sAmt', 'sBank', 'sDay', 'sStart', 'sEnd');
  document.getElementById('sCycle').value = 'mensal';
  document.getElementById('editSubId').value = '';
  const subTitleEl = document.getElementById('subTitle');
  if (subTitleEl) subTitleEl.firstChild.textContent = 'Nova Assinatura ';
  S.subOwner = 'mine';
  S.subSplitPeople = [''];
  S.subSplitType = 'equal';
  S.subSplitValues = null;
  S._editSubId = null;
  setSubOwner('mine');

  const histSection = document.getElementById('sHistorySection');
  if (histSection) histSection.style.display = 'none';

  if (editId) {
    const s = (S.subscriptions || []).find(x => String(x.id) === String(editId));
    if (s) {
      document.getElementById('editSubId').value = String(s.id);
      if (subTitleEl) subTitleEl.firstChild.textContent = 'Editar Assinatura ';
      document.getElementById('sName').value = s.name || '';
      document.getElementById('sAmt').value = s.amount || '';
      document.getElementById('sCycle').value = s.cycle || 'mensal';
      document.getElementById('sBank').value = s.bank || '';
      document.getElementById('sDay').value = s.day || '';
      document.getElementById('sStart').value = s.startDate || '';
      document.getElementById('sEnd').value = s.endDate || '';
      S.subOwner = s.owner || 'mine';
      S.subSplitPeople = s.splitPeople ? [...s.splitPeople] : [''];
      S.subSplitType = (s.splitValues && s.splitValues.length) ? 'fixed' : 'equal';
      S.subSplitValues = s.splitValues ? [...s.splitValues] : null;
      setSubOwner(S.subOwner);
      if (S.subOwner === 'other' && s.splitPeople?.[0]) {
        document.getElementById('sOtherPerson').value = s.splitPeople[0];
      }
      if (S.subOwner === 'split') {
        setSubSplitType(S.subSplitType);
        renderSubSplitUI();
        updateSubSplitHint();
      }
      // Histórico de preço
      S._editSubId = String(s.id);
      if (histSection) histSection.style.display = 'block';
      closeReajusteForm();
      _renderSubHistoryInModal(s);
    }
  }
  openModal('mSub');
}

// ── Helpers de histórico de preço ──
function _getEffectiveHistory(s) {
  if (s.priceHistory && s.priceHistory.length) return s.priceHistory;
  if (s.startDate) return [{ amount: s.amount, from: s.startDate, note: 'Valor inicial' }];
  return [{ amount: s.amount, from: '', note: 'Valor inicial' }];
}

function _renderSubHistoryInModal(s) {
  const el = document.getElementById('sHistoryList');
  if (!el) return;
  const h = _getEffectiveHistory(s);
  if (h.length <= 1) {
    el.innerHTML = `<div style="font-size:12px;color:var(--text3);padding:4px 0">Nenhum reajuste registrado ainda.</div>`;
    return;
  }
  el.innerHTML = h.map((entry, i) => {
    const isLast = i === h.length - 1;
    const pct = i > 0 ? ((entry.amount - h[i - 1].amount) / h[i - 1].amount * 100).toFixed(1) : null;
    return `<div style="display:flex;align-items:center;gap:8px;padding:6px 0;${isLast ? '' : 'border-bottom:1px solid var(--border)'}">
      <div style="flex:1">
        <span style="font-size:13px;font-family:var(--mono);${isLast ? 'color:var(--accent);font-weight:600' : 'color:var(--text2)'}">R$&nbsp;${fmt(entry.amount)}</span>
        ${entry.note ? `<span style="font-size:11px;color:var(--text3);margin-left:6px">${entry.note}</span>` : ''}
      </div>
      <div style="text-align:right;flex-shrink:0">
        <div style="font-size:11px;color:var(--text3);font-family:var(--mono)">${(entry.from || '').replace('-', '/')}</div>
        <div style="font-size:11px;color:${pct ? 'var(--orange)' : 'var(--text3)'}">
          ${pct ? '↑ +' + pct + '%' : 'inicial'}
        </div>
      </div>
    </div>`;
  }).join('');
}

function openReajusteForm() {
  document.getElementById('sReajusteForm').style.display = 'block';
  document.getElementById('sReajusteBtn').style.display = 'none';
  document.getElementById('sReajusteAmt').value = '';
  document.getElementById('sReajusteDate').value = '';
  document.getElementById('sReajusteNote').value = '';
}

function closeReajusteForm() {
  const form = document.getElementById('sReajusteForm');
  const btn  = document.getElementById('sReajusteBtn');
  if (form) form.style.display = 'none';
  if (btn)  btn.style.display  = 'inline-flex';
}

async function confirmReajuste() {
  const newAmt = parseFloat(document.getElementById('sReajusteAmt').value);
  const date   = document.getElementById('sReajusteDate').value;
  const note   = document.getElementById('sReajusteNote').value.trim();

  if (isNaN(newAmt) || newAmt <= 0) { alert('Informe o novo valor.'); return; }
  if (!date) { alert('Informe o mês do reajuste.'); return; }

  const sub = (S.subscriptions || []).find(s => String(s.id) === String(S._editSubId));
  if (!sub) return;

  if (!sub.priceHistory || !sub.priceHistory.length) {
    sub.priceHistory = [{ amount: sub.amount, from: sub.startDate || '', note: 'Valor inicial' }];
  }
  sub.priceHistory.push({ amount: newAmt, from: date, note });
  sub.amount = newAmt;

  // Atualiza campo de valor no modal
  const amtEl = document.getElementById('sAmt');
  if (amtEl) amtEl.value = newAmt;

  setSyncing(true);
  await dbSaveSub(sub);
  setSyncing(false);

  closeReajusteForm();
  _renderSubHistoryInModal(sub);
  renderSubs();
  showToast('✓ Reajuste registrado');
}

async function saveSub() {
  const name = document.getElementById('sName').value.trim();
  const amt = parseFloat(document.getElementById('sAmt').value);
  const cycle = document.getElementById('sCycle').value;
  const bank = document.getElementById('sBank').value.trim();
  const day = document.getElementById('sDay').value;
  const startDate = document.getElementById('sStart').value;
  const endDate = document.getElementById('sEnd').value;
  const editId = document.getElementById('editSubId').value;
  const owner = S.subOwner || 'mine';

  if (!name || isNaN(amt) || amt <= 0) { alert('Preencha nome e valor.'); return; }
  if (!startDate) { alert('Informe a data de início.'); return; }

  let splitPeople = null;
  let splitValues = null;
  if (owner === 'other') {
    const person = normalizeName(document.getElementById('sOtherPerson').value);
    if (!person) { alert('Informe o nome da pessoa.'); return; }
    splitPeople = [person];
  } else if (owner === 'split') {
    splitPeople = (S.subSplitPeople || []).filter(Boolean).map(normalizeName);
    if (!splitPeople.length) { alert('Adicione ao menos uma pessoa para dividir.'); return; }
    if (S.subSplitType === 'fixed') {
      splitValues = (S.subSplitValues || splitPeople.map(() => 0)).slice(0, splitPeople.length);
    }
  }

  if (!S.subscriptions) S.subscriptions = [];

  let priceHistory = null;
  if (editId) {
    const existing = S.subscriptions.find(s => String(s.id) === String(editId));
    if (existing) priceHistory = existing.priceHistory || null;
    S.subscriptions = S.subscriptions.filter(s => String(s.id) !== String(editId));
    await dbDeleteSub(editId);
  } else {
    priceHistory = [{ amount: amt, from: startDate, note: 'Valor inicial' }];
  }

  const sub = {
    id: editId ? String(editId) : String(Date.now()),
    name, amount: amt, cycle, bank, day,
    startDate, endDate: endDate || null,
    owner, splitPeople, splitValues, priceHistory
  };
  S.subscriptions.push(sub);
  setSyncing(true);
  await dbSaveSub(sub);
  setSyncing(false);
  renderSubs();
  closeModal('mSub');
  showToast('✓ Assinatura salva');
}

async function deleteSub(id) {
  if (!confirm('Excluir assinatura?')) return;
  S.subscriptions = S.subscriptions.filter(s => String(s.id) !== String(id));
  setSyncing(true);
  await dbDeleteSub(id);
  setSyncing(false);
  renderSubs();
  showToast('Assinatura excluída');
}

function toggleSubEvolution(id) {
  const el  = document.getElementById('subEvo_' + id);
  const btn = document.getElementById('subEvoBtn_' + id);
  if (!el) return;
  const showing = el.style.display !== 'none';
  el.style.display  = showing ? 'none' : 'block';
  if (btn) btn.textContent = showing ? '📈 ver evolução' : '📈 ocultar';
}

function _buildSparkline(history) {
  if (!history || history.length < 2) return '';
  const W = 240, H = 52, PAD = 8;
  const now = Date.now();
  const pts = history.map(h => ({
    t: new Date(((h.from || '2000-01') + '-01')).getTime(),
    y: h.amount
  }));
  pts.push({ t: now, y: pts[pts.length - 1].y });

  const minT = pts[0].t, maxT = now;
  const amts = history.map(h => h.amount);
  const minY = Math.min(...amts) * 0.88;
  const maxY = Math.max(...amts) * 1.08;
  const rangeY = maxY - minY || 1;
  const rangeT = maxT - minT || 1;

  const px = t => (PAD + ((t - minT) / rangeT) * (W - PAD * 2)).toFixed(1);
  const py = y => ((H - PAD) - ((y - minY) / rangeY) * (H - PAD * 2)).toFixed(1);

  let d = `M ${px(pts[0].t)} ${py(pts[0].y)}`;
  for (let i = 1; i < pts.length; i++) {
    d += ` H ${px(pts[i].t)} V ${py(pts[i].y)}`;
  }
  const fillD = d + ` V ${H - PAD} H ${px(pts[0].t)} Z`;

  const dots = history.map(h => {
    const x = px(new Date(((h.from || '2000-01') + '-01')).getTime());
    const y = py(h.amount);
    return `<circle cx="${x}" cy="${y}" r="3.5" fill="var(--accent)" stroke="var(--bg2)" stroke-width="1.5"/>`;
  }).join('');

  return `<svg width="${W}" height="${H}" viewBox="0 0 ${W} ${H}" style="display:block;overflow:visible;margin-bottom:8px">
    <path d="${fillD}" fill="var(--accent)" opacity="0.08"/>
    <path d="${d}" fill="none" stroke="var(--accent)" stroke-width="2" stroke-linejoin="round"/>
    ${dots}
  </svg>`;
}

function renderSubs() {
  const el = document.getElementById('subsContent');
  if (!el) return;

  if (!S.subscriptions || !S.subscriptions.length) {
    el.innerHTML = `
      <div style="display:flex;justify-content:flex-end;margin-bottom:16px">
        <button class="btn btn-primary btn-sm" onclick="openSubM()">+ Assinatura</button>
      </div>
      <div class="empty">nenhuma assinatura cadastrada</div>`;
    return;
  }

  const active = S.subscriptions.filter(s => !s.endDate);
  const cancelled = S.subscriptions.filter(s => s.endDate);
  const mensal = active.filter(s => s.cycle === 'mensal').reduce((t, s) => t + calcMySubPart(s), 0);

  const byBank = {};
  const noBank = [];
  active.forEach(s => {
    if (s.bank) {
      if (!byBank[s.bank]) byBank[s.bank] = [];
      byBank[s.bank].push(s);
    } else {
      noBank.push(s);
    }
  });

  const card = s => {
    const owner = s.owner || 'mine';
    const myPart = calcMySubPart(s);
    const history = _getEffectiveHistory(s);
    const hasHistory = history.length > 1;
    const initialAmt = history[0].amount;
    const totalPct = hasHistory
      ? ((s.amount - initialAmt) / initialAmt * 100).toFixed(0)
      : null;

    const ownerBadge = owner === 'other'
      ? `<span class="bm bm-other" style="font-size:10px;margin-left:4px">${(s.splitPeople || ['?'])[0]}</span>`
      : owner === 'split'
        ? `<span class="bm bm-split" style="font-size:10px;margin-left:4px">÷${(s.splitPeople || []).length + 1}</span>`
        : '';
    const reajusteBadge = hasHistory
      ? `<span class="bm" style="font-size:10px;margin-left:4px;background:rgba(251,146,60,.15);color:var(--orange)">↑ +${totalPct}%</span>`
      : '';
    const myPartLabel = owner !== 'mine'
      ? `<div style="font-size:10px;color:var(--accent);font-family:var(--mono);margin-top:2px">meu: R$&nbsp;${fmt(myPart)}</div>`
      : '';

    const evoSection = hasHistory ? `
      <div id="subEvo_${s.id}" style="display:none;margin-top:10px;padding-top:10px;border-top:1px solid var(--border)">
        ${_buildSparkline(history)}
        ${history.map((h, i) => {
          const isLast = i === history.length - 1;
          const pct = i > 0
            ? ((h.amount - history[i - 1].amount) / history[i - 1].amount * 100).toFixed(1)
            : null;
          return `<div style="display:flex;justify-content:space-between;align-items:center;padding:5px 0;${isLast ? '' : 'border-bottom:1px solid var(--border)'}">
            <div>
              <span style="font-family:var(--mono);font-size:12px;${isLast ? 'color:var(--accent);font-weight:600' : 'color:var(--text2)'}">R$&nbsp;${fmt(h.amount)}</span>
              ${h.note ? `<span style="font-size:10px;color:var(--text3);margin-left:5px">${h.note}</span>` : ''}
            </div>
            <div style="text-align:right">
              <div style="font-size:10px;color:var(--text3);font-family:var(--mono)">${(h.from || '').replace('-', '/')}</div>
              <div style="font-size:10px;color:${isLast ? 'var(--accent)' : pct ? 'var(--orange)' : 'var(--text3)'}">
                ${isLast ? 'atual' : pct ? '↑ +' + pct + '%' : 'inicial'}
              </div>
            </div>
          </div>`;
        }).join('')}
      </div>
      <button id="subEvoBtn_${s.id}" onclick="event.stopPropagation();toggleSubEvolution('${s.id}')"
        style="background:none;border:none;color:var(--text3);font-size:11px;cursor:pointer;padding:6px 0 0;width:100%;text-align:left">
        📈 ver evolução
      </button>` : '';

    return `
    <div class="scard">
      <div style="position:absolute;top:8px;right:8px;display:flex;gap:3px">
        <button style="background:none;border:none;color:var(--text3);cursor:pointer;font-size:13px;padding:2px 4px;border-radius:4px;transition:color .15s"
          onmouseover="this.style.color='var(--accent)'" onmouseout="this.style.color='var(--text3)'"
          onclick="openSubM('${s.id}')">✎</button>
        <button style="background:none;border:none;color:var(--text3);cursor:pointer;font-size:13px;padding:2px 4px;border-radius:4px;transition:color .15s"
          onmouseover="this.style.color='var(--red)'" onmouseout="this.style.color='var(--text3)'"
          onclick="deleteSub('${s.id}')">×</button>
      </div>
      <div class="scard-name">${s.name}${ownerBadge}${reajusteBadge}</div>
      <div class="scard-amt">R$&nbsp;${fmt(s.amount)}</div>
      ${myPartLabel}
      <div class="scard-det">
        ${s.cycle}${s.day ? ' · dia ' + s.day : ''}${s.bank ? ' · ' + s.bank : ''}
        ${s.startDate ? ' · desde ' + s.startDate.replace('-', '/') : ''}
      </div>
      ${evoSection}
    </div>`;
  };

  let html = `
    <div style="display:flex;justify-content:flex-end;margin-bottom:16px">
      <button class="btn btn-primary btn-sm" onclick="openSubM()">+ Assinatura</button>
    </div>
    <div class="summary-grid" style="margin-bottom:22px">
      <div class="card">
        <div class="card-lbl">Total Mensal</div>
        <div class="card-val a">R$ ${fmt(mensal)}</div>
        <div class="card-sub">${active.filter(s => s.cycle === 'mensal').length} ativa(s)</div>
      </div>
      <div class="card card-link" onclick="toggleSubProjection()" title="Ver detalhes por serviço">
        <div class="card-lbl">Projeção Anual ↗</div>
        <div class="card-val">R$ ${fmt(calcAnualTotal(active))}</div>
        <div class="card-sub">clique para detalhar</div>
      </div>
      ${cancelled.length ? `
      <div class="card">
        <div class="card-lbl">Canceladas</div>
        <div class="card-val" style="color:var(--text3)">${cancelled.length}</div>
      </div>` : ''}
    </div>`;

  // ── Projeção Anual Detalhada ──
  const projFiltered = _subProjFilter === 'all' ? active
    : active.filter(s => (s.owner || 'mine') === _subProjFilter);
  const projList = [...projFiltered]
    .map(s => {
      const anual = s.cycle === 'anual' ? s.amount : s.cycle === 'semanal' ? s.amount * 52 : s.amount * 12;
      const mensal_val = s.cycle === 'anual' ? s.amount / 12 : s.cycle === 'semanal' ? s.amount * 52 / 12 : s.amount;
      return { ...s, anual, mensal_val };
    })
    .sort((a, b) => b.anual - a.anual);
  const maxProj = Math.max(...projList.map(s => s.anual), 1);

  const filterChips = ['all', 'mine', 'other', 'split'].map(f => {
    const labels = { all: 'Tudo', mine: 'Minhas', other: 'De outros', split: 'Em conjunto' };
    return `<div class="chip ${_subProjFilter === f ? 'sel' : ''}" onclick="setSubProjFilter('${f}')">${labels[f]}</div>`;
  }).join('');

  html += `
    <div id="subProjection" style="display:none;margin-bottom:24px">
      <div style="display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:8px;margin-bottom:12px">
        <div class="sec-title">Projeção por Serviço (12 meses)</div>
        <div class="chips">${filterChips}</div>
      </div>
      ${projList.length === 0 ? `<div class="empty" style="padding:20px 0">nenhuma assinatura nesta categoria</div>` : `<div class="tbl-block">
        <table>
          <thead><tr><th>Serviço</th><th>Ciclo</th><th style="text-align:right">Mensal</th><th style="text-align:right">Anual</th></tr></thead>
          <tbody>
            ${projList.map(s => `
              <tr>
                <td>
                  ${s.name}
                  <div style="margin-top:4px;height:4px;border-radius:2px;background:var(--bg4);overflow:hidden">
                    <div style="height:100%;width:${(s.anual / maxProj * 100).toFixed(1)}%;background:var(--accent);border-radius:2px"></div>
                  </div>
                </td>
                <td><span class="bm bm-cat">${s.cycle}</span></td>
                <td style="text-align:right;font-family:var(--mono);font-size:12px;color:var(--text2)">R$ ${fmt(s.mensal_val)}</td>
                <td style="text-align:right;font-family:var(--mono);font-size:13px;color:var(--accent)">R$ ${fmt(s.anual)}</td>
              </tr>`).join('')}
          </tbody>
        </table>
        <div class="foot-row">
          <div class="foot-grp"><span class="foot-lbl">Total Anual</span><span class="foot-amt" style="color:var(--accent)">R$ ${fmt(calcAnualTotal(projFiltered))}</span></div>
          <div class="foot-grp"><span class="foot-lbl">Média Mensal</span><span class="foot-amt">R$ ${fmt(calcAnualTotal(projFiltered) / 12)}</span></div>
        </div>
      </div>`}
    </div>`;

  Object.entries(byBank).forEach(([bank, subs]) => {
    const bt = subs.filter(s => s.cycle === 'mensal').reduce((t, s) => t + s.amount, 0);
    html += `
      <div style="margin-bottom:18px">
        <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px">
          <div class="sec-title">${bank}</div>
          <div style="font-family:var(--mono);font-size:11px;color:var(--text3)">R$ ${fmt(bt)}/mês</div>
        </div>
        <div class="sub-grid">${subs.map(card).join('')}</div>
      </div>`;
  });

  if (noBank.length) {
    html += `
      <div style="margin-bottom:18px">
        <div class="sec-title" style="margin-bottom:10px">Sem banco</div>
        <div class="sub-grid">${noBank.map(card).join('')}</div>
      </div>`;
  }

  if (cancelled.length) {
    html += `
      <div class="divider"></div>
      <div class="sec-title" style="margin-bottom:10px;color:var(--text3)">Canceladas</div>
      <div class="sub-grid">
        ${cancelled.map(s => `
        <div class="scard" style="opacity:.45">
          <div style="position:absolute;top:8px;right:8px">
            <button style="background:none;border:none;color:var(--text3);cursor:pointer;font-size:13px"
              onclick="deleteSub(${s.id})">×</button>
          </div>
          <div class="scard-name" style="text-decoration:line-through">${s.name}</div>
          <div class="scard-amt" style="color:var(--text3)">R$ ${fmt(s.amount)}</div>
          <div class="scard-det">cancelada ${s.endDate.replace('-', '/')}</div>
        </div>`).join('')}
      </div>`;
  }

  el.innerHTML = html;
}

/* ── js/dashboard.js ── */
// ══════════════════════════════════════════════════
// DASHBOARD.JS — Renderização do Dashboard Principal
// ══════════════════════════════════════════════════

function filterEntries(q) {
  const v = q.toLowerCase().trim();
  document.querySelectorAll('#view-dash .entry-row').forEach(row => {
    row.style.display = !v || row.textContent.toLowerCase().includes(v) ? '' : 'none';
  });
}

function setInnerTab(t) {
  S.currentInnerTab = t;
  document.querySelectorAll('.itab').forEach(x => x.classList.remove('active'));
  document.querySelectorAll('.itab-content').forEach(x => x.style.display = 'none');
  document.getElementById('itab-' + t)?.classList.add('active');
  const c = document.getElementById('itabc-' + t);
  if (c) {
    c.style.display = 'block';
  }
}

// ── Sub-funções extraídas de renderDash() ──

function renderGoalBar(m, metaGasto) {
  if (!m.goal) return '';
  const pct = metaGasto / m.goal * 100;
  const cor = metaGasto > m.goal
    ? 'var(--red)'
    : pct > 80
      ? 'var(--orange)'
      : 'var(--green)';
  const restam = m.goal - metaGasto;
  return `
      <div class="goal-bar-wrap" style="margin-top:6px">
        <div class="goal-bar-track">
          <div class="goal-bar-fill" style="width:${Math.min(pct, 100).toFixed(1)}%;background:${cor}"></div>
        </div>
        <div class="goal-bar-label">
          ${pct.toFixed(0)}% da meta ·
          ${restam > 0 ? `R$ ${fmt(restam)} restam` : `R$ ${fmt(Math.abs(restam))} acima`}
        </div>
      </div>`;
}

function renderAlerts(m, metaGasto, recL) {
  let alerts = '';
  if (m.goal) {
    const pct = metaGasto / m.goal;
    if (pct > 0.8 && metaGasto <= m.goal)
      alerts += `<div class="alert-banner">⚠️ Você usou ${(pct * 100).toFixed(0)}% da sua meta de gastos este mês.</div>`;
    if (metaGasto > m.goal)
      alerts += `<div class="alert-banner" style="background:#ff4d4d18;border-color:#ff4d4d44;color:var(--red)">🚨 Meta ultrapassada em R$ ${fmt(metaGasto - m.goal)}.</div>`;
  }
  const today_d = new Date();
  (recL || []).forEach(r => {
    if (r.day) {
      const diff = parseInt(r.day) - today_d.getDate();
      if (diff >= 0 && diff <= 3)
        alerts += `<div class="alert-banner">📅 ${r.desc} vence ${diff === 0 ? 'hoje' : diff === 1 ? 'amanhã' : `em ${diff} dias`} (dia ${r.day}).</div>`;
    }
  });
  return alerts;
}

function renderSummaryCards(m, totals) {
  const { totalGasto, metaGasto, othT, incMyT, incOthT, saldo, subM, mySubM, othSubM, pplMap, goalBar } = totals;
  return `
    <div class="summary-grid">
      <div class="card">
        <div class="card-lbl">Total Gastos</div>
        <div class="card-val">R$ ${fmt(totalGasto)}</div>
      </div>
      <div class="card card-link" onclick="showMeusGastosReport()" title="Ver detalhes dos meus gastos">
        <div class="card-lbl">Meus Gastos ↗</div>
        <div class="card-val a">R$ ${fmt(metaGasto)}</div>
        ${goalBar || '<div class="card-sub">clique para ver</div>'}
      </div>
      ${Object.keys(pplMap).length > 0 ? `<div class="card card-link" onclick="toggleAReceber()" title="Ver quem deve — clique para expandir">
        <div class="card-lbl">A Receber ↗</div>
        <div class="card-val b">R$ ${fmt(Object.values(pplMap).reduce((s, d) => s + d.total, 0))}</div>
        <div class="card-sub">${Object.keys(pplMap).length} pessoa(s) · clique para ver</div>
      </div>` : `<div class="card"><div class="card-lbl">A Receber</div><div class="card-val b">R$ 0,00</div><div class="card-sub">ninguém deve</div></div>`}
      <div class="card card-link" onclick="setInnerTab('entradas')" title="Ver entradas do mês">
        <div class="card-lbl">Entradas ↗</div>
        <div class="card-val g">R$ ${fmt(incMyT + incOthT)}</div>
        <div class="card-sub">clique para ver</div>
      </div>
      <div class="card"><div class="card-lbl">Saldo</div><div class="card-val ${saldo >= 0 ? 'g' : 'r'}">R$ ${fmt(saldo)}</div></div>
      ${subM > 0 ? `<div class="card card-link" onclick="showView('subs')" title="Gerenciar assinaturas">
        <div class="card-lbl">Assinaturas ↗</div>
        <div class="card-val p">R$ ${fmt(subM)}</div>
        <div class="card-sub">${mySubM > 0 ? `meu: R$ ${fmt(mySubM)}` : ''}${othSubM > 0 ? ` · terceiros: R$ ${fmt(othSubM)}` : ''} · clique para ver</div>
      </div>` : ''}
    </div>`;
}

function renderAReceber(pplMap) {
  if (!Object.keys(pplMap).length) return '';
  return `
    <div id="dashAReceber" style="display:none;margin-bottom:4px">
      <div class="sec-title" style="margin-bottom:10px">A Receber</div>
      <div class="people-grid" style="margin-bottom:18px">
        ${Object.entries(pplMap).map(([n, d]) => `
          <div class="pcard" onclick="openCobranca('${n}')" style="cursor:pointer" title="Cobrar ${n}">
            <div class="pcard-name">${n}</div>
            <div class="pcard-val">R$ ${fmt(d.total)}</div>
            <div class="pcard-sub">${d.count} item(s) · toque para cobrar</div>
          </div>`).join('')}
      </div>
    </div>`;
}

function toggleAReceber() {
  const el = document.getElementById('dashAReceber');
  if (!el) return;
  el.style.display = el.style.display === 'none' ? 'block' : 'none';
}

function renderBankSection(m, bk) {
  if (!m.banks.length) return '';
  const bkTabs = m.banks.map(b => `
    <div class="btab ${S.currentBank === b.name ? 'active' : ''}" onclick="selectBank('${b.name}')">
      <span class="dot" style="color:${PALETTE[b.color] || PALETTE.azure}"></span>
      ${b.name}
      <button onclick="event.stopPropagation();deleteBank('${b.name}')"
        style="background:none;border:none;color:var(--text3);cursor:pointer;font-size:14px;padding:0 2px;margin-left:2px;line-height:1;transition:color .15s"
        onmouseover="this.style.color='var(--red)'"
        onmouseout="this.style.color='var(--text3)'"
        title="Excluir banco">×</button>
    </div>`).join('') + `<button class="btab" onclick="openModal('mBank')" style="opacity:.5">+</button>`;

  let html = `<div class="sec-title" style="margin-bottom:8px">Bancos</div><div class="bank-tabs">${bkTabs}</div>`;

  if (bk) {
    const sorted = [...bk.entries].sort((a, b_) => new Date(b_.date) - new Date(a.date));
    const bMine = sorted.filter(e => e.owner === 'mine').reduce((s, e) => s + e.amount, 0);
    const bOth  = sorted.filter(e => e.owner === 'other').reduce((s, e) => s + e.amount, 0);
    const rows = sorted.length ? sorted.map(e => {
      const ib = e.type === 'installment'
        ? `<span class="bm bm-inst">${e.installCurrent ?? '?'}/${e.installTotal ?? '?'}</span>`
        : e.type === 'pix' ? `<span class="bm bm-pix">pix</span>`
        : e.type === 'debit' ? `<span class="bm bm-debit">débito</span>`
        : e.type === 'cash' ? `<span class="bm bm-cash">dinheiro</span>` : '';
      const splitN = (e.splitPeople?.length ?? (e.person ? 1 : 0)) + 1;
      const wb = e.owner === 'split'
        ? `<span class="bm bm-split">÷${splitN}</span>`
        : e.owner === 'other'
          ? `<span class="bm bm-other">${e.person}</span>`
          : `<span class="bm bm-mine">eu</span>`;
      const amtColor = e.owner === 'other' ? 'var(--blue)' : e.owner === 'split' ? 'var(--purple)' : 'var(--text)';
      const icon = getCategoryIcon(e.desc, e.category);
      const safeE = JSON.stringify(e).replace(/'/g, "&#39;").replace(/"/g, "&quot;");
      return `<tr class="entry-row" data-entry-id="${e.id}" data-bank="${bk.name}"
        onclick='showEntryDetail(${safeE}, "${bk.name}")'>
        <td>${icon ? icon + ' ' : ''}${e.desc} ${ib}</td>
        <td>${wb}</td>
        <td><span class="amt" style="color:${amtColor}">R$ ${fmt(e.amount)}</span></td>
      </tr>`;
    }).join('') : `<tr><td colspan="3"><div class="empty" style="padding:20px">nenhum lançamento</div></td></tr>`;

    html += `
      <div class="tbl-block">
        <div class="tbl-head">
          <span class="tbl-title">${bk.name}</span>
          <span class="tbl-total">R$ ${fmt(bMine + bOth)}</span>
        </div>
        <table>
          <thead><tr><th>Descrição</th><th>De quem</th><th>Valor</th></tr></thead>
          <tbody>${rows}</tbody>
        </table>
        ${sorted.length ? `
          <div class="foot-row">
            <div class="foot-grp"><span class="foot-lbl">Meus</span><span class="foot-amt" style="color:var(--accent)">R$ ${fmt(bMine)}</span></div>
            <div class="foot-grp"><span class="foot-lbl">Outros</span><span class="foot-amt" style="color:var(--blue)">R$ ${fmt(bOth)}</span></div>
            <div class="foot-grp"><span class="foot-lbl">Total</span><span class="foot-amt">R$ ${fmt(bMine + bOth)}</span></div>
          </div>` : ''}
      </div>`;
  }
  return html;
}

function renderPixSection(pixL, pixT) {
  if (!pixL.length) return '';
  const prows = [...pixL].sort((a, b_) => new Date(b_.date) - new Date(a.date)).map(p => `
    <tr class="entry-row" onclick="openPixM(${p.id})">
      <td>${p.to}${p.obs ? ` <span style="color:var(--text3);font-size:11px">· ${p.obs}</span>` : ''}
        ${p.bank ? ` <span class="bm bm-cat">${p.bank}</span>` : ''}</td>
      <td><span class="bm bm-pix">pix</span></td>
      <td><span class="amt" style="color:var(--green)">R$ ${fmt(p.amount)}</span></td>
    </tr>`).join('');
  return `
    <div class="tbl-block">
      <div class="tbl-head"><span class="tbl-title">Pix Enviados</span><span class="tbl-total" style="color:var(--green)">R$ ${fmt(pixT)}</span></div>
      <table><thead><tr><th>Para</th><th>Tipo</th><th>Valor</th></tr></thead><tbody>${prows}</tbody></table>
    </div>`;
}

function renderRecurrentsSection(recL, recT) {
  if (!recL.length) return '';
  const rrows = recL.map(r => `
    <tr class="entry-row" onclick="openRecM(${r.id})">
      <td>${r.desc}${r.day ? ` <span style="color:var(--text3);font-size:11px">· dia ${r.day}</span>` : ''}</td>
      <td><span class="bm bm-rec">fixo</span></td>
      <td><span class="amt" style="color:var(--orange)">R$ ${fmt(r.amount)}</span></td>
    </tr>`).join('');
  return `
    <div class="tbl-block">
      <div class="tbl-head"><span class="tbl-title">Contas Fixas</span><span class="tbl-total" style="color:var(--orange)">R$ ${fmt(recT)}</span></div>
      <table><thead><tr><th>Descrição</th><th>Tipo</th><th>Valor</th></tr></thead><tbody>${rrows}</tbody></table>
    </div>`;
}

function renderEntradasSection(incL, incMyT, incOthT, incPplMap) {
  if (!incL.length) {
    return `
      <div style="display:flex;justify-content:flex-end;margin-bottom:14px">
        <button class="btn btn-green btn-sm" onclick="openIncomeM()">+ Entrada</button>
      </div>
      <div class="empty">nenhuma entrada</div>`;
  }

  const rows = [...incL].sort((a, b_) => new Date(b_.date) - new Date(a.date)).map(i => {
    const incType = i.incType || 'Outros';
    const typeBadge = incType === 'Pix' ? `<span class="bm bm-pix">pix</span>`
      : incType === 'Débito' ? `<span class="bm bm-debit">débito</span>`
      : incType === 'Dinheiro' ? `<span class="bm bm-cash">dinheiro</span>`
      : `<span class="bm bm-cat">${incType}</span>`;
    return `<tr class="entry-row" onclick="openIncomeM('${String(i.id).replace(/'/g,"\\'")}')">
      <td>${i.desc} ${typeBadge}${i.from ? ` <span style="color:var(--text3);font-size:11px">· ${i.from}</span>` : ''}</td>
      <td>${i.owner === 'other' ? `<span class="bm bm-other">${i.person}</span>` : `<span class="bm bm-mine">meu</span>`}</td>
      <td><span class="amt" style="color:var(--green)">R$ ${fmt(i.amount)}</span></td>
    </tr>`;
  }).join('');

  let html = '';
  if (Object.keys(incPplMap).length)
    html += `
      <div class="sec-title" style="margin-bottom:10px">Quem me deve</div>
      <div class="people-grid" style="margin-bottom:18px">
        ${Object.entries(incPplMap).map(([n, t]) => `
          <div class="pcard">
            <div class="pcard-name">${n}</div>
            <div class="pcard-val" style="color:var(--green)">R$ ${fmt(t)}</div>
            <div class="pcard-sub">a receber</div>
          </div>`).join('')}
      </div>`;

  html += `
    <div style="display:flex;justify-content:flex-end;margin-bottom:12px">
      <button class="btn btn-green btn-sm" onclick="openIncomeM()">+ Entrada</button>
    </div>
    <div class="tbl-block">
      <div class="tbl-head">
        <span class="tbl-title">Todas as Entradas</span>
        <span class="tbl-total" style="color:var(--green)">R$ ${fmt(incMyT + incOthT)}</span>
      </div>
      <table><thead><tr><th>Descrição</th><th>De quem</th><th>Valor</th></tr></thead><tbody>${rows}</tbody></table>
      <div class="foot-row">
        <div class="foot-grp"><span class="foot-lbl">Meu</span><span class="foot-amt" style="color:var(--green)">R$ ${fmt(incMyT)}</span></div>
        <div class="foot-grp"><span class="foot-lbl">De outros</span><span class="foot-amt" style="color:var(--blue)">R$ ${fmt(incOthT)}</span></div>
        <div class="foot-grp"><span class="foot-lbl">Total</span><span class="foot-amt">R$ ${fmt(incMyT + incOthT)}</span></div>
      </div>
    </div>`;
  return html;
}

function showMeusGastosReport() {
  const m = getMonth();
  if (!m) return;

  document.getElementById('meusGastosTitle').textContent = 'Meus Gastos — ' + m.label + ' ' + m.year;

  const allE = m.banks.flatMap(b => b.entries.map(e => ({ ...e, bankName: b.name })));
  const pixL = S.pixEntries[S.currentMonth] || [];
  const recL = S.recurrents[S.currentMonth] || [];

  const myEntries = allE.filter(e => e.owner === 'mine');
  const splitEntries = allE.filter(e => e.owner === 'split');
  const myEntriesAmt = myEntries.reduce((s, e) => s + e.amount, 0);
  const splitAmt = splitEntries.reduce((s, e) => s + e.amount * (e.splitRatio ?? 0.5), 0);
  const pixTotal = pixL.reduce((s, p) => s + p.amount, 0);
  const recTotal = recL.reduce((s, r) => s + r.amount, 0);
  const mySubs = (S.subscriptions || []).filter(s => !s.endDate && s.cycle === 'mensal');
  const mySubTotal = mySubs.reduce((s, sub) => s + calcMySubPart(sub), 0);
  const grandTotal = myEntriesAmt + splitAmt + pixTotal + recTotal + mySubTotal;

  const mkEntryRow = (e) => {
    const myAmt = e.owner === 'split' ? e.amount * (e.splitRatio ?? 0.5) : e.amount;
    const icon = getCategoryIcon(e.desc, e.category);
    const typeBadge = e.type === 'installment'
      ? `<span class="bm bm-inst">${e.installCurrent ?? '?'}/${e.installTotal ?? '?'}</span>`
      : e.type === 'debit' ? `<span class="bm bm-debit">déb</span>`
      : e.type === 'cash' ? `<span class="bm bm-cash">din</span>` : '';
    const splitBadge = e.owner === 'split' ? `<span class="bm bm-split">÷</span>` : '';
    return `<tr><td>${icon ? icon + ' ' : ''}${e.desc} ${typeBadge}${splitBadge}</td>
      <td style="color:var(--text2);font-size:12px">${e.bankName}</td>
      <td style="text-align:right"><span class="amt">R$ ${fmt(myAmt)}</span></td></tr>`;
  };

  const entryRows = [...myEntries, ...splitEntries]
    .sort((a, b) => new Date(b.date) - new Date(a.date))
    .map(mkEntryRow).join('');

  const pixRows = [...pixL]
    .sort((a, b) => new Date(b.date) - new Date(a.date))
    .map(p => `<tr><td>${p.to}${p.obs ? ` <span style="color:var(--text3);font-size:11px">· ${p.obs}</span>` : ''}</td>
      <td style="color:var(--text2);font-size:12px">pix</td>
      <td style="text-align:right"><span class="amt">R$ ${fmt(p.amount)}</span></td></tr>`).join('');

  const recRows = recL.map(r => `<tr>
    <td>${r.desc}${r.day ? ` <span style="color:var(--text3);font-size:11px">· dia ${r.day}</span>` : ''}</td>
    <td style="color:var(--text2);font-size:12px">fixo</td>
    <td style="text-align:right"><span class="amt">R$ ${fmt(r.amount)}</span></td></tr>`).join('');

  const subRows = mySubs.map(s => {
    const myPart = calcMySubPart(s);
    const splitBadge = s.owner === 'split' || s.owner === 'other' ? `<span class="bm bm-split">÷</span>` : '';
    return `<tr><td>${s.name} ${splitBadge}</td>
      <td style="color:var(--text2);font-size:12px">assinatura</td>
      <td style="text-align:right"><span class="amt">R$ ${fmt(myPart)}</span></td></tr>`;
  }).join('');

  const mkSection = (label, rows) => rows ? `
    <tr><td colspan="3" style="padding:10px 0 4px;font-size:11px;color:var(--text3);text-transform:uppercase;letter-spacing:1px;font-weight:600">${label}</td></tr>
    ${rows}` : '';

  const allRows = mkSection('Lançamentos', entryRows)
    + mkSection('Pix', pixRows)
    + mkSection('Contas Fixas', recRows)
    + mkSection('Assinaturas', subRows);

  document.getElementById('meusGastosContent').innerHTML = `
    <div class="summary-grid" style="margin-bottom:20px">
      ${myEntriesAmt + splitAmt > 0 ? `<div class="card"><div class="card-lbl">Lançamentos</div><div class="card-val a">R$ ${fmt(myEntriesAmt + splitAmt)}</div></div>` : ''}
      ${pixTotal > 0 ? `<div class="card"><div class="card-lbl">Pix</div><div class="card-val a">R$ ${fmt(pixTotal)}</div></div>` : ''}
      ${recTotal > 0 ? `<div class="card"><div class="card-lbl">Contas Fixas</div><div class="card-val a">R$ ${fmt(recTotal)}</div></div>` : ''}
      ${mySubTotal > 0 ? `<div class="card"><div class="card-lbl">Assinaturas</div><div class="card-val a">R$ ${fmt(mySubTotal)}</div></div>` : ''}
      <div class="card"><div class="card-lbl">Total Meus</div><div class="card-val a" style="font-size:18px">R$ ${fmt(grandTotal)}</div></div>
    </div>
    ${allRows ? `<div class="tbl-block"><table><thead><tr><th>Descrição</th><th>Onde</th><th style="text-align:right">Meu valor</th></tr></thead><tbody>${allRows}</tbody></table></div>`
      : '<div class="empty">Nenhum gasto registrado</div>'}`;

  openModal('mMeusGastos');
}

// ── renderDash(): calcula totais, chama sub-funções, monta innerHTML ──
let _renderDashRaf = null;
function renderDash() {
  if (_renderDashRaf) return;
  _renderDashRaf = requestAnimationFrame(() => {
    _renderDashRaf = null;
    _renderDashImpl();
  });
}
function _renderDashImpl() {
  // Invalida cache de views derivadas ao mudar dados
  S._repKey = null;
  S._yearKey = null;
  S._histKey = null;

  const m = getMonth();
  const el = document.getElementById('dashContent');
  if (!el) return;
  if (!m) {
    const temMeses = S.months && S.months.length > 0;

    if (!temMeses) {
      // Nunca criou nenhum mês — ícone azul + botão criar
      el.innerHTML = `
      <div class="empty-state">
        <div class="empty-state-icon">
          <svg width="56" height="56" viewBox="0 0 52 52" fill="none">
            <rect x="6" y="12" width="40" height="30" rx="5" fill="#1a2a3a" stroke="#4d9eff" stroke-width="1.5"/>
            <line x1="6" y1="21" x2="46" y2="21" stroke="#4d9eff" stroke-width="1"/>
            <rect x="12" y="27" width="9" height="5" rx="1.5" fill="#4d9eff" opacity=".5"/>
            <rect x="26" y="27" width="13" height="5" rx="1.5" fill="#4d9eff" opacity=".25"/>
            <rect x="12" y="34" width="20" height="3" rx="1.5" fill="#4d9eff" opacity=".15"/>
            <circle cx="40" cy="36" r="8" fill="#0a0a0a" stroke="#4d9eff" stroke-width="1.5"/>
            <line x1="40" y1="32.5" x2="40" y2="39.5" stroke="#4d9eff" stroke-width="1.8" stroke-linecap="round"/>
            <line x1="36.5" y1="36" x2="43.5" y2="36" stroke="#4d9eff" stroke-width="1.8" stroke-linecap="round"/>
          </svg>
        </div>
        <div class="empty-state-title blue">nenhum mês ainda</div>
        <div class="empty-state-sub">crie seu primeiro mês para começar</div>
        <div class="empty-state-dots blue">
          <span></span><span></span><span></span>
        </div>
        <div class="empty-state-btn-wrap">
          <button class="btn btn-primary btn-sm" onclick="openModal('mMonth')">+ novo mês</button>
        </div>
      </div>`;
    } else {
      // Tem meses mas nenhum selecionado — ícone verde + instrução
      el.innerHTML = `
      <div class="empty-state">
        <div class="empty-state-icon">
          <svg width="56" height="56" viewBox="0 0 52 52" fill="none">
            <rect x="6" y="12" width="40" height="30" rx="5" fill="#1a2a1a" stroke="#5aad5a" stroke-width="1.5"/>
            <line x1="6" y1="21" x2="46" y2="21" stroke="#5aad5a" stroke-width="1"/>
            <rect x="12" y="27" width="9" height="5" rx="1.5" fill="#5aad5a" opacity=".5"/>
            <rect x="26" y="27" width="13" height="5" rx="1.5" fill="#5aad5a" opacity=".25"/>
            <rect x="12" y="34" width="20" height="3" rx="1.5" fill="#5aad5a" opacity=".15"/>
            <circle cx="40" cy="36" r="8" fill="#0a0a0a" stroke="#5aad5a" stroke-width="1.5"/>
            <polyline points="36.5,36 39,38.5 43.5,33" stroke="#5aad5a" stroke-width="1.8"
              stroke-linecap="round" stroke-linejoin="round" fill="none"/>
          </svg>
        </div>
        <div class="empty-state-title green">selecione um mês</div>
        <div class="empty-state-sub">escolha na sidebar para ver seus dados</div>
        <div class="empty-state-dots green">
          <span></span><span></span><span></span>
        </div>
      </div>`;
    }
    return;
  }
  
  const allE = m.banks.flatMap(b => b.entries.map(e => ({ ...e, bankName: b.name })));
  const pixL = S.pixEntries[S.currentMonth] || [];
  const recL = S.recurrents[S.currentMonth] || [];
  const incL = S.incomes[S.currentMonth] || [];

  const myT  = allE.filter(e => e.owner === 'mine').reduce((s, e) => s + e.amount, 0)
    + allE.filter(e => e.owner === 'split').reduce((s, e) => s + e.amount * (e.splitRatio ?? 0.5), 0);
  const othT = allE.filter(e => e.owner === 'other').reduce((s, e) => s + e.amount, 0)
    + allE.filter(e => e.owner === 'split').reduce((s, e) => s + e.amount * (1 - (e.splitRatio ?? 0.5)), 0);
  const pixT = pixL.reduce((s, p) => s + p.amount, 0);
  const recT = recL.reduce((s, r) => s + r.amount, 0);

  // ── Assinaturas: calcular partes e A Receber de terceiros ──
  let mySubM = 0, othSubM = 0;
  const subPplMap = {};
  (S.subscriptions || []).filter(s => s.cycle === 'mensal' && isSubActiveInMonth(s, S.currentMonth)).forEach(s => {
    const owner = s.owner || 'mine';
    const myPart = calcMySubPart(s);
    mySubM += myPart;
    if (owner === 'other') {
      const person = (s.splitPeople || ['?'])[0];
      othSubM += s.amount;
      if (!subPplMap[person]) subPplMap[person] = { total: 0, count: 0 };
      subPplMap[person].total += s.amount;
      subPplMap[person].count++;
    } else if (owner === 'split') {
      const othPart = s.amount - myPart;
      othSubM += othPart;
      const people = s.splitPeople || [];
      people.forEach((p, i) => {
        const share = s.splitValues ? (s.splitValues[i] || 0) : othPart / people.length;
        if (!subPplMap[p]) subPplMap[p] = { total: 0, count: 0 };
        subPplMap[p].total += share;
        subPplMap[p].count++;
      });
    }
  });
  const subM = mySubM + othSubM;
  const totalGasto = myT + othT + pixT + recT;

  // ── Meta considera gastos do usuário + minha parte das assinaturas mensais ──
  const metaGasto = myT + pixT + recT + mySubM;

  const incMyT  = incL.filter(i => i.owner === 'mine').reduce((s, i) => s + i.amount, 0);
  const incOthT = incL.filter(i => i.owner === 'other').reduce((s, i) => s + i.amount, 0);
  const saldo = incMyT - metaGasto;

  const pplMap = {};
  allE.filter(e => e.owner === 'other').forEach(e => {
    if (!pplMap[e.person]) pplMap[e.person] = { total: 0, count: 0 };
    pplMap[e.person].total += e.amount;
    pplMap[e.person].count++;
  });
  allE.filter(e => e.owner === 'split').forEach(e => {
    const people = (e.splitPeople || (e.person ? e.person.split(', ') : [])).filter(Boolean);
    if (!people.length) return;
    const count = e.splitCount || (people.length + 1);
    const myRatio = e.splitRatio ?? (1 / count);
    const share = e.amount * (1 - myRatio) / people.length;
    people.forEach(p => {
      if (!pplMap[p]) pplMap[p] = { total: 0, count: 0 };
      pplMap[p].total += share;
      pplMap[p].count++;
    });
  });
  // Mescla assinaturas de terceiros no pplMap principal
  Object.entries(subPplMap).forEach(([p, d]) => {
    if (!pplMap[p]) pplMap[p] = { total: 0, count: 0 };
    pplMap[p].total += d.total;
    pplMap[p].count += d.count;
  });

  const incPplMap = {};
  incL.filter(i => i.owner === 'other').forEach(i => {
    if (!incPplMap[i.person]) incPplMap[i.person] = 0;
    incPplMap[i.person] += i.amount;
  });

  const bk = m.banks.find(b => b.name === S.currentBank) || m.banks[0];
  if (bk) S.currentBank = bk.name;

  // ── Monta seção de gastos ──
  let gastoHTML = '';
  if (!m.banks.length && !recL.length && !pixL.length) {
    gastoHTML = `
      <div class="empty-state">
        <div class="empty-state-icon">
          <svg width="56" height="56" fill="none" stroke="currentColor" stroke-width="1.5" viewBox="0 0 24 24" style="opacity:.35">
            <rect x="2" y="5" width="20" height="14" rx="2"/>
            <line x1="2" y1="10" x2="22" y2="10"/>
          </svg>
        </div>
        <div class="empty-state-title">Nenhum lançamento ainda</div>
        <div class="empty-state-sub">Comece registrando seu primeiro gasto do mês.</div>
        <button class="btn btn-primary" onclick="openEntryM()" style="margin-top:18px">+ Adicionar Lançamento</button>
      </div>`;
  } else {
    gastoHTML += renderBankSection(m, bk);
    gastoHTML += renderPixSection(pixL, pixT);
    gastoHTML += renderRecurrentsSection(recL, recT);
  }

  const goalBar = renderGoalBar(m, metaGasto);
  const totals = { totalGasto, metaGasto, othT, incMyT, incOthT, saldo, subM, mySubM, othSubM, pplMap, goalBar };

  el.innerHTML = `
    ${renderAlerts(m, metaGasto, recL)}
    ${renderSummaryCards(m, totals)}
    ${renderAReceber(pplMap)}
    <div style="position:relative;margin-bottom:14px">
      <svg style="position:absolute;left:11px;top:50%;transform:translateY(-50%);pointer-events:none;color:var(--text3)" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.35-4.35"/></svg>
      <input type="text" id="globalSearch" placeholder="Buscar lançamento..." oninput="filterEntries(this.value)"
        style="padding-left:34px;background:var(--bg2);border:1px solid var(--border);border-radius:8px;width:100%;box-sizing:border-box;font-size:13px;color:var(--text)">
    </div>
    <div class="inner-tabs">
      <div class="itab active" id="itab-gastos" onclick="setInnerTab('gastos')">Gastos</div>
      <div class="itab" id="itab-entradas" onclick="setInnerTab('entradas')">Entradas</div>
    </div>
    <div class="itab-content" id="itabc-gastos">
      <div style="display:flex;gap:7px;flex-wrap:wrap;margin-bottom:18px">
        <button class="btn btn-primary btn-sm" onclick="openEntryM()">+ Lançamento</button>
        <button class="btn btn-ghost btn-sm" onclick="openModal('mBank')">+ Banco</button>
        <button class="btn btn-ghost btn-sm" onclick="openPixM()">+ Pix</button>
        <button class="btn btn-ghost btn-sm" onclick="openRecM()">+ Conta Fixa</button>
      </div>
      ${gastoHTML}
    </div>
    <div class="itab-content" id="itabc-entradas" style="display:none">${renderEntradasSection(incL, incMyT, incOthT, incPplMap)}</div>`;

  if (S.currentInnerTab === 'entradas') {
    document.getElementById('itab-entradas')?.classList.add('active');
    document.getElementById('itab-gastos')?.classList.remove('active');
    document.getElementById('itabc-gastos').style.display = 'none';
    document.getElementById('itabc-entradas').style.display = 'block';
  }

  initSwipeRows();
}

/* ── js/cobranca.js ── */
// ══════════════════════════════════════════════════
// COBRANCA.JS — Cobrança de Terceiros
// ══════════════════════════════════════════════════

let _cobData = null;

function openCobranca(person) {
  const m = getMonth();
  if (!m) return;

  const cartao = m.banks.flatMap(b =>
    b.entries
      .filter(e => e.owner === 'other' && e.person === person)
      .map(e => ({ ...e, bankName: b.name, _tipo: 'cartao' }))
  );

  const splitCartao = m.banks.flatMap(b =>
    b.entries
      .filter(e => {
        if (e.owner !== 'split') return false;
        const people = (e.splitPeople || (e.person ? e.person.split(', ') : [])).filter(Boolean);
        return people.includes(person);
      })
      .map(e => {
        const people = (e.splitPeople || (e.person ? e.person.split(', ') : [])).filter(Boolean);
        const count = e.splitCount || (people.length + 1);
        const myRatio = e.splitRatio ?? (1 / count);
        const share = e.amount * (1 - myRatio) / people.length;
        return { ...e, amount: share, bankName: b.name, _tipo: 'cartao', desc: e.desc + ' (dividido)' };
      })
  );

  const pix = (S.pixEntries[m.key] || [])
    .filter(p => p.to === person)
    .map(p => ({
      id: p.id, desc: `Pix${p.obs ? ' — ' + p.obs : ''}`,
      amount: p.amount, date: p.date, bankName: p.bank,
      _tipo: 'pix', type: 'pix', category: null,
      installCurrent: null, installTotal: null
    }));

  const subs = (S.subscriptions || [])
    .filter(s => {
      if (s.endDate) return false;
      const owner = s.owner || 'mine';
      if (owner === 'other') return (s.splitPeople || [])[0] === person;
      if (owner === 'split') return (s.splitPeople || []).includes(person);
      return false;
    })
    .map(s => {
      const owner = s.owner || 'mine';
      let share;
      if (owner === 'other') {
        share = s.amount;
      } else {
        const people = s.splitPeople || [];
        const idx = people.indexOf(person);
        const myPart = calcMySubPart(s);
        share = s.splitValues?.[idx] ?? ((s.amount - myPart) / people.length);
      }
      return {
        id: s.id, desc: s.name + ' (assinatura)',
        amount: share, bankName: s.bank || '—',
        _tipo: 'sub', type: 'sub',
        category: null, installCurrent: null, installTotal: null
      };
    });

  const allItems = [...cartao, ...splitCartao, ...pix, ...subs];
  const total    = allItems.reduce((s, e) => s + e.amount, 0);

  _cobData = { person, items: allItems, total, month: m };

  const el = document.getElementById('mCobrancaContent');
  if (!el) return;

  el.innerHTML = `
    <div style="text-align:center;padding:12px 0 20px">
      <div style="font-size:30px;font-weight:700;font-family:var(--mono);color:var(--blue)">R$ ${fmt(total)}</div>
      <div style="font-size:13px;color:var(--text2);margin-top:4px;font-weight:500">${person}</div>
      <div style="font-size:11px;color:var(--text3);font-family:var(--mono)">${m.label} ${m.year} · ${allItems.length} item(s)</div>
    </div>
    <div class="tbl-block" style="margin-bottom:16px">
      <table>
        <thead><tr><th>Descrição</th><th>Banco</th><th>Valor</th></tr></thead>
        <tbody>
          ${allItems.map(e => `
            <tr>
              <td>
                ${e.desc}
                ${e.installCurrent ? `<span class="bm bm-inst" style="margin-left:4px">${e.installCurrent}/${e.installTotal}</span>` : ''}
                ${e._tipo === 'pix' ? `<span class="bm bm-pix" style="margin-left:4px">pix</span>` : ''}
                ${e._tipo === 'sub' ? `<span class="bm bm-rec" style="margin-left:4px">assinatura</span>` : ''}
                ${e.category ? `<span class="bm bm-cat" style="margin-left:4px">${e.category}</span>` : ''}
              </td>
              <td style="color:var(--text3);font-size:12px;font-family:var(--mono)">${e.bankName || '—'}</td>
              <td><span class="amt">R$ ${fmt(e.amount)}</span></td>
            </tr>`).join('')}
        </tbody>
      </table>
    </div>
    <div class="modal-actions">
      <button class="btn btn-ghost" onclick="copiarCobranca('simples')">📋 Simples</button>
      <button class="btn btn-primary" onclick="copiarCobranca('completo')">💬 Completo</button>
    </div>`;

  openModal('mCobranca');
}

function copiarCobranca(tipo) {
  if (!_cobData) return;
  const { person, items, total, month } = _cobData;

  let texto;
  if (tipo === 'simples') {
    const linhas = items.map(e => {
      let l = `• ${e.desc}: R$ ${fmt(e.amount)}`;
      if (e.installCurrent) l += ` ${e.installCurrent}/${e.installTotal}`;
      return l;
    }).join('\n');
    texto = `${person} — ${month.label} ${month.year}:\n${linhas}\n─────────────────\nTotal: R$ ${fmt(total)}`;
  } else {
    const linhas = items.map(e => {
      let l = `• ${e.desc}: R$ ${fmt(e.amount)}`;
      if (e.installCurrent) l += ` (parcela ${e.installCurrent}/${e.installTotal})`;
      if (e._tipo === 'pix') l += ' (pix)';
      return l;
    }).join('\n');
    texto = `💰 ${person}\n📅 ${month.label} ${month.year}\n\n${linhas}\n\n═══════════════════\n💵 Total: R$ ${fmt(total)}`;
  }

  const fallback = () => {
    const ta = document.createElement('textarea');
    ta.value = texto;
    ta.style.cssText = 'position:fixed;opacity:0;top:0;left:0';
    document.body.appendChild(ta);
    ta.focus(); ta.select();
    try { document.execCommand('copy'); } catch {}
    document.body.removeChild(ta);
    showToast('📋 Cobrança copiada!');
  };

  if (navigator.clipboard) {
    navigator.clipboard.writeText(texto)
      .then(() => showToast('📋 Cobrança copiada!'))
      .catch(fallback);
  } else {
    fallback();
  }
}

/* ── js/reports.js ── */
// ══════════════════════════════════════════════════
// REPORTS.JS — Relatórios, Resumo Anual
// ══════════════════════════════════════════════════

const _rc = {};
function _destroyChart(k) { if (_rc[k]) { _rc[k].destroy(); delete _rc[k]; } }
function _makeChart(k, id, cfg) {
  _destroyChart(k);
  const cv = document.getElementById(id);
  if (!cv || typeof Chart === 'undefined') return;
  _rc[k] = new Chart(cv.getContext('2d'), cfg);
}

const CAT_COLORS = ['#4d9eff', '#a78bfa', '#fb923c', '#4ade80', '#f472b6', '#facc15', '#38bdf8', '#f87171', '#34d399', '#e879f9'];
const MONO_FONT = "'DM Mono', monospace";

function _chartDefaults() {
  return {
    grid: getCSSVar('--border') || '#1e1e1e',
    text: getCSSVar('--text3') || '#555',
    tick: { color: getCSSVar('--text3') || '#555', font: { size: 10, family: MONO_FONT } }
  };
}

function _avatarColor(name) {
  const colors = [
    { bg: '#152035', fg: '#4d9eff' },
    { bg: '#1e1230', fg: '#a78bfa' },
    { bg: '#0f2a1a', fg: '#4ade80' },
    { bg: '#2a1800', fg: '#fb923c' },
    { bg: '#2a0f0f', fg: '#f87171' },
    { bg: '#0f2a2a', fg: '#38bdf8' },
  ];
  let hash = 0;
  for (let i = 0; i < name.length; i++) hash = name.charCodeAt(i) + ((hash << 5) - hash);
  return colors[Math.abs(hash) % colors.length];
}


// ══════════════════════════════════════════════════
// REPORTS — Picker de mês (tela inicial)
// ══════════════════════════════════════════════════
let _repPickerYear = null;

function renderReports() {
  const el = document.getElementById('repContent');
  if (!el) return;

  const subEl = document.getElementById('tbSub');
  if (subEl) subEl.textContent = 'selecione um mês';

  if (!S.months.length) {
    el.innerHTML = '<div class="empty">nenhum mês cadastrado</div>';
    return;
  }

  const years = [...new Set(S.months.map(m => +m.year))].sort((a, b) => b - a);
  if (!_repPickerYear || !years.includes(_repPickerYear)) {
    _repPickerYear = years[0];
  }

  const yearTabs = years.map(y =>
    `<div class="itab ${y === _repPickerYear ? 'active' : ''}" onclick="_repPickerYear=${y};renderReports()">${y}</div>`
  ).join('');

  const mths = [...S.months].filter(m => +m.year === _repPickerYear).reverse();

  const cards = mths.map(m => {
    const allE = m.banks.flatMap(b => b.entries);
    const pixL = S.pixEntries[m.key] || [];
    const recL = S.recurrents[m.key] || [];
    const incL = S.incomes[m.key] || [];
    const gasto    = allE.reduce((s, e) => s + e.amount, 0) + pixL.reduce((s, p) => s + p.amount, 0) + recL.reduce((s, r) => s + r.amount, 0);
    const entrada  = incL.reduce((s, i) => s + i.amount, 0);
    const meusGastos = allE.filter(e => e.owner === 'mine').reduce((s, e) => s + e.amount, 0)
                     + allE.filter(e => e.owner === 'split').reduce((s, e) => s + e.amount * (e.splitRatio ?? 0.5), 0)
                     + pixL.reduce((s, p) => s + p.amount, 0) + recL.reduce((s, r) => s + r.amount, 0);
    const saldo    = entrada - meusGastos;
    const nLanc    = allE.length + pixL.length + recL.length;
    const hasMeta  = m.goal && gasto > 0;
    const pct      = hasMeta ? Math.min(gasto / m.goal * 100, 100).toFixed(0) : null;
    const metaColor = hasMeta ? (gasto > m.goal ? 'var(--red)' : +pct > 80 ? 'var(--orange)' : 'var(--accent)') : 'var(--accent)';
    return `<div class="rep-mc" onclick="renderReportForMonth('${m.key}')">
      <div class="rep-mc-hd">
        <span class="rep-mc-name">${m.label}</span>
        <span class="rep-mc-yr">${m.year}</span>
      </div>
      <div class="rep-mc-total">R$&nbsp;${fmt(gasto)}</div>
      <div class="rep-mc-row">
        <span class="rep-mc-lbl">Entradas</span>
        <span class="rep-mc-val" style="color:var(--green)">R$&nbsp;${fmt(entrada)}</span>
      </div>
      <div class="rep-mc-row">
        <span class="rep-mc-lbl">Saldo</span>
        <span class="rep-mc-val" style="color:${saldo >= 0 ? 'var(--green)' : 'var(--red)'}">${saldo >= 0 ? '+' : '−'}R$&nbsp;${fmt(Math.abs(saldo))}</span>
      </div>
      <div class="rep-mc-entries">${nLanc ? nLanc + ' lançamentos' : 'sem lançamentos'}</div>
      ${hasMeta ? `<div class="rep-mc-bar"><div class="rep-mc-bar-fill" style="width:${pct}%;background:${metaColor}"></div></div><div class="rep-mc-meta">${pct}% da meta</div>` : ''}
    </div>`;
  }).join('');

  el.innerHTML = `
    <div class="inner-tabs" style="margin-bottom:20px">${yearTabs}</div>
    <div class="rep-mc-grid">${cards || '<div class="empty">nenhum mês neste ano</div>'}</div>
  `;
}

// ── Abre o relatório de um mês específico ──
function renderReportForMonth(key) {
  const m = S.months.find(x => x.key === key);
  const el = document.getElementById('repContent');
  if (!el || !m) return;

  const subEl = document.getElementById('tbSub');
  if (subEl) subEl.textContent = m.label + ' ' + m.year;

  el.innerHTML = `
    <div style="margin-bottom:16px">
      <button class="btn btn-ghost btn-sm" onclick="renderReports()" style="gap:6px">
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="15 18 9 12 15 6"/></svg>
        Todos os Meses
      </button>
    </div>
    <div id="repMonthBody"></div>
  `;
  _buildMonthReport(m, document.getElementById('repMonthBody'));
}

// ══════════════════════════════════════════════════
// REPORTS — Corpo do relatório mensal
// ══════════════════════════════════════════════════
function _buildMonthReport(m, el) {
  if (!el) return;

  const allE = m.banks.flatMap(b => b.entries.map(e => ({ ...e, bankName: b.name })));
  const pixL = S.pixEntries[m.key] || [];
  const recL = S.recurrents[m.key] || [];
  const incL = S.incomes[m.key] || [];

  const myT = allE.filter(e => e.owner === 'mine').reduce((s, e) => s + e.amount, 0);
  const othT = allE.filter(e => e.owner === 'other').reduce((s, e) => s + e.amount, 0);
  const pixT = pixL.reduce((s, p) => s + p.amount, 0);
  const recT = recL.reduce((s, r) => s + r.amount, 0);
  const incT = incL.reduce((s, i) => s + i.amount, 0);
  const totalGasto = myT + othT + pixT + recT;
  const saldo = incT - (myT + pixT + recT);

  const fallbackColors = ['#4d9eff', '#a78bfa', '#fb923c', '#4ade80', '#f472b6', '#facc15'];
  const bkRaw = m.banks.map(b => ({
    name: b.name,
    total: b.entries.reduce((s, e) => s + e.amount, 0),
    mine: b.entries.filter(e => e.owner === 'mine').reduce((s, e) => s + e.amount, 0),
    others: b.entries.filter(e => e.owner === 'other').reduce((s, e) => s + e.amount, 0),
    color: PALETTE[b.color] || PALETTE.azure
  }));
  const rawCores = bkRaw.map(x => x.color);
  const bkColors = bkRaw.map((b, i) =>
    rawCores.filter(c => c === b.color).length > 1 ? fallbackColors[i % fallbackColors.length] : b.color
  );

  const pplMap = {};
  allE.filter(e => e.owner === 'other').forEach(e => {
    pplMap[e.person] = (pplMap[e.person] || 0) + e.amount;
  });
  const pplItems = n => allE.filter(e => e.owner === 'other' && e.person === n).length;

  const catMap = {};
  allE.filter(e => e.category).forEach(e => {
    catMap[e.category] = (catMap[e.category] || 0) + e.amount;
  });
  const catSorted = Object.entries(catMap).sort((a, b) => b[1] - a[1]);

  const mIdx = S.months.findIndex(x => x.key === m.key);
  const prevM = mIdx > 0 ? S.months[mIdx - 1] : null;
  const prevTotal = prevM ? monthTotal(prevM) : null;

  let mySubRep = 0, splitSubRep = 0;
  (S.subscriptions || []).filter(s => !s.endDate && s.cycle === 'mensal').forEach(s => {
    if ((s.owner || 'mine') === 'mine') { mySubRep += s.amount; }
    else if (s.owner === 'split') {
      const myPart = calcMySubPart(s);
      mySubRep += myPart;
      splitSubRep += s.amount - myPart;
    }
  });

  const incTypeMap = {};
  incL.forEach(i => { const t = i.incType || 'Outros'; incTypeMap[t] = (incTypeMap[t] || 0) + i.amount; });

  const typeMap = { normal: 0, installment: 0, pix: pixT, debit: 0, cash: 0 };
  allE.forEach(e => {
    if (e.type === 'installment') typeMap.installment += e.amount;
    else if (e.type === 'debit') typeMap.debit += e.amount;
    else if (e.type === 'cash') typeMap.cash += e.amount;
    else typeMap.normal += e.amount;
  });
  typeMap.normal += recT;
  const tiposSorted = [
    { label: 'Normal / Fixo', val: typeMap.normal, color: getCSSVar('--accent') || '#4d9eff' },
    { label: 'Parcelado', val: typeMap.installment, color: '#fb923c' },
    { label: 'Pix', val: typeMap.pix, color: '#4ade80' },
    { label: 'Débito', val: typeMap.debit, color: '#38bdf8' },
    { label: 'Dinheiro', val: typeMap.cash, color: '#facc15' },
    { label: 'Assinaturas', val: mySubRep, color: '#a78bfa' },
    { label: 'Em conjunto', val: splitSubRep, color: '#f472b6' },
  ].filter(t => t.val > 0);

  const dailyMap = {};
  allE.forEach(e => { if (e.date) { const d = +e.date.split('-')[2]; dailyMap[d] = (dailyMap[d] || 0) + e.amount; } });
  pixL.forEach(p => { if (p.date) { const d = +p.date.split('-')[2]; dailyMap[d] = (dailyMap[d] || 0) + p.amount; } });
  const monthIdx = ['Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho', 'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'].indexOf(m.label);
  const daysInMonth = new Date(m.year, monthIdx + 1, 0).getDate() || 30;
  const dailyLabels = Array.from({ length: daysInMonth }, (_, i) => i + 1);
  let acum = 0;
  const dailyData = dailyLabels.map(d => { acum += dailyMap[d] || 0; return acum; });

  const allMonths = S.months;
  const annualLabels = allMonths.map(mn => mn.label.slice(0, 3));
  const annualGastos = allMonths.map(mn => monthTotal(mn));
  const annualEntradas = allMonths.map(mn => (S.incomes[mn.key] || []).reduce((s, i) => s + i.amount, 0));
  const hasAnnual = annualGastos.some(v => v > 0) || annualEntradas.some(v => v > 0);

  el.innerHTML = `
    <div class="summary-grid" style="margin-bottom:16px">
      <div class="card"><div class="card-lbl">Total Gastos</div><div class="card-val">R$&nbsp;${fmt(totalGasto)}</div></div>
      <div class="card"><div class="card-lbl">Meus</div><div class="card-val a">R$&nbsp;${fmt(myT + pixT + recT)}</div></div>
      <div class="card"><div class="card-lbl">A Receber</div><div class="card-val b">R$&nbsp;${fmt(othT)}</div></div>
      <div class="card"><div class="card-lbl">Entradas</div><div class="card-val g">R$&nbsp;${fmt(incT)}</div></div>
      <div class="card"><div class="card-lbl">Saldo</div><div class="card-val ${saldo >= 0 ? 'g' : 'r'}">R$&nbsp;${fmt(saldo)}</div></div>
    </div>

    <div class="rep-row">
      <div class="rep-card">
        <div class="rep-card-title">Comparativo Mensal</div>
        ${prevM ? `
          <div style="position:relative;height:110px"><canvas id="repComparativo"></canvas></div>
          <div style="font-size:11px;font-family:var(--mono);margin-top:8px;color:${totalGasto > prevTotal ? 'var(--red)' : 'var(--green)'}">
            ${totalGasto > prevTotal
        ? `▲ R$&nbsp;${fmt(totalGasto - prevTotal)} a mais que ${prevM.label}`
        : `▼ R$&nbsp;${fmt(prevTotal - totalGasto)} a menos que ${prevM.label}`}
          </div>
        ` : `<div style="height:110px;display:flex;align-items:center;justify-content:center;font-size:11px;color:var(--text3)">apenas um mês cadastrado</div>`}
      </div>
      <div class="rep-card">
        <div class="rep-card-title">Por Banco</div>
        <div class="rep-donut-wrap">
          <div style="position:relative;width:120px;height:120px;flex-shrink:0">
            <canvas id="repBankDonut"></canvas>
          </div>
          <div class="rep-donut-legend">
            ${bkRaw.map((b, i) => `
              <div class="rep-legend-item">
                <div class="rep-legend-dot" style="background:${bkColors[i]}"></div>
                <span class="rep-legend-name">${b.name}</span>
                <span class="rep-legend-val">R$&nbsp;${fmt(b.total)}</span>
              </div>
              <div class="rep-legend-sub">meu: R$&nbsp;${fmt(b.mine)} · outros: R$&nbsp;${fmt(b.others)}</div>
            `).join('')}
          </div>
        </div>
      </div>
    </div>

    <div class="rep-row">
      <div class="rep-card">
        <div class="rep-card-title">Por Categoria</div>
        ${catSorted.length ? `
          <div style="position:relative;height:${Math.max(catSorted.slice(0, 6).length * 36 + 10, 110)}px">
            <canvas id="repCat"></canvas>
          </div>
        ` : `<div style="height:110px;display:flex;align-items:center;justify-content:center;font-size:11px;color:var(--text3)">sem categorias</div>`}
      </div>
      <div class="rep-card">
        <div class="rep-card-title">Evolução Diária</div>
        <div style="position:relative;height:150px"><canvas id="repEvol"></canvas></div>
      </div>
    </div>

    ${Object.keys(pplMap).length ? `
      <div class="sec-title" style="margin:4px 0 12px">A Receber por Pessoa</div>
      <div class="rep-ppl-grid">
        ${Object.entries(pplMap).sort((a, b) => b[1] - a[1]).map(([n, t]) => {
          const av = _avatarColor(n);
          const initials = n.split(' ').map(w => w[0]).join('').slice(0, 2).toUpperCase();
          const cnt = pplItems(n);
          return `<div class="rep-pcard" onclick="openCobranca('${n}')">
            <div class="rep-pcard-avatar" style="background:${av.bg};color:${av.fg}">${initials}</div>
            <div class="rep-pcard-name">${n}</div>
            <div class="rep-pcard-val">R$&nbsp;${fmt(t)}</div>
            <div class="rep-pcard-sub">${cnt}&nbsp;${cnt === 1 ? 'item' : 'itens'}</div>
          </div>`;
        }).join('')}
      </div>
    ` : ''}

    ${tiposSorted.length ? `
      <div class="rep-card" style="margin-bottom:12px">
        <div class="rep-card-title">Por Tipo</div>
        <div style="position:relative;height:${tiposSorted.length * 36 + 20}px">
          <canvas id="repTipo"></canvas>
        </div>
      </div>
    ` : ''}

    ${Object.keys(incTypeMap).length ? `
      <div class="rep-card" style="margin-bottom:12px">
        <div class="rep-card-title">Entradas por Tipo</div>
        ${(() => {
        const maxInc = Math.max(...Object.values(incTypeMap), 1);
        return Object.entries(incTypeMap).sort((a, b) => b[1] - a[1]).map(([t, v]) => {
          const color = t === 'Pix' ? 'var(--green)' : t === 'Débito' ? 'var(--teal)' : t === 'Dinheiro' ? 'var(--yellow)' : t === 'Salário' ? 'var(--accent)' : t === 'Freela' ? 'var(--blue)' : 'var(--text3)';
          return `<div class="bar-wrap">
              <div class="bar-lbl"><span>${t}</span><span>R$&nbsp;${fmt(v)}</span></div>
              <div class="bar-track"><div class="bar-fill" style="width:${(v / maxInc * 100).toFixed(1)}%;background:${color}"></div></div>
            </div>`;
        }).join('');
      })()}
      </div>
    ` : ''}

    ${hasAnnual ? `
      <div class="rep-card">
        <div class="rep-card-title">Entradas vs Gastos — Visão Anual</div>
        <div style="position:relative;height:190px"><canvas id="repAnual"></canvas></div>
      </div>
    ` : ''}
  `;

  // ── Charts do relatório mensal ─────────────────────────────────────────────
  const d = _chartDefaults();
  const fmtT = v => ' R$ ' + Number(v).toLocaleString('pt-BR', { minimumFractionDigits: 2 });

  if (prevM) {
    _makeChart('repComp', 'repComparativo', {
      type: 'bar',
      data: {
        labels: [m.label.slice(0, 3) + ' ' + m.year, prevM.label.slice(0, 3) + ' ' + prevM.year],
        datasets: [{ data: [totalGasto, prevTotal], backgroundColor: [getCSSVar('--accent') || '#4d9eff', '#252528'], borderRadius: 4, borderSkipped: false }]
      },
      options: {
        indexAxis: 'y', responsive: true, maintainAspectRatio: false,
        plugins: { legend: { display: false }, tooltip: { callbacks: { label: ctx => fmtT(ctx.raw) } } },
        scales: {
          x: { grid: { color: d.grid }, ticks: d.tick, border: { display: false } },
          y: { grid: { display: false }, ticks: { ...d.tick, color: getCSSVar('--text2') || '#888' }, border: { display: false } }
        }
      }
    });
  }

  if (bkRaw.length) {
    _makeChart('repDonut', 'repBankDonut', {
      type: 'doughnut',
      data: { labels: bkRaw.map(b => b.name), datasets: [{ data: bkRaw.map(b => b.total), backgroundColor: bkColors, borderWidth: 0, borderRadius: 4, spacing: 3 }] },
      options: { responsive: true, maintainAspectRatio: false, cutout: '72%', plugins: { legend: { display: false }, tooltip: { callbacks: { label: ctx => fmtT(ctx.parsed) } } } }
    });
  }

  _makeChart('repEvol', 'repEvol', {
    type: 'line',
    data: {
      labels: dailyLabels,
      datasets: [{
        data: dailyData, borderColor: '#4d9eff',
        backgroundColor: ctx => {
          const g = ctx.chart.ctx.createLinearGradient(0, 0, 0, 150);
          g.addColorStop(0, 'rgba(77,158,255,0.15)');
          g.addColorStop(1, 'rgba(77,158,255,0)');
          return g;
        },
        borderWidth: 2, fill: true, tension: 0.4, pointRadius: 0, pointHoverRadius: 4,
      }]
    },
    options: {
      responsive: true, maintainAspectRatio: false,
      plugins: { legend: { display: false }, tooltip: { callbacks: { label: ctx => fmtT(ctx.parsed.y) } } },
      scales: {
        x: { grid: { color: d.grid }, ticks: { ...d.tick, maxTicksLimit: 8 }, border: { display: false } },
        y: { grid: { color: d.grid }, ticks: d.tick, border: { display: false } }
      }
    }
  });

  if (tiposSorted.length) {
    _makeChart('repTipo', 'repTipo', {
      type: 'bar',
      data: { labels: tiposSorted.map(t => t.label), datasets: [{ data: tiposSorted.map(t => t.val), backgroundColor: tiposSorted.map(t => t.color), borderRadius: 4, borderSkipped: false }] },
      options: {
        indexAxis: 'y', responsive: true, maintainAspectRatio: false,
        plugins: { legend: { display: false }, tooltip: { callbacks: { label: ctx => fmtT(ctx.parsed.x) } } },
        scales: {
          x: { grid: { color: d.grid }, ticks: d.tick, border: { display: false } },
          y: { grid: { display: false }, ticks: { ...d.tick, color: d.text }, border: { display: false } }
        }
      }
    });
  }

  if (catSorted.length) {
    const topCats = catSorted.slice(0, 6);
    _makeChart('repCat', 'repCat', {
      type: 'bar',
      data: { labels: topCats.map(([c]) => getCategoryIcon(c, c) + ' ' + c), datasets: [{ data: topCats.map(([, v]) => v), backgroundColor: topCats.map((_, i) => CAT_COLORS[i % CAT_COLORS.length]), borderRadius: 4, borderSkipped: false }] },
      options: {
        indexAxis: 'y', responsive: true, maintainAspectRatio: false,
        plugins: { legend: { display: false }, tooltip: { callbacks: { label: ctx => fmtT(ctx.parsed.x) } } },
        scales: {
          x: { grid: { color: d.grid }, ticks: d.tick, border: { display: false } },
          y: { grid: { display: false }, ticks: { ...d.tick, color: d.text }, border: { display: false } }
        }
      }
    });
  }

  if (hasAnnual) {
    _makeChart('repAnual', 'repAnual', {
      type: 'bar',
      data: {
        labels: annualLabels,
        datasets: [
          { label: 'Gastos', data: annualGastos, backgroundColor: '#4d9eff', borderRadius: 3, borderSkipped: false },
          { label: 'Entradas', data: annualEntradas, backgroundColor: '#4ade80', borderRadius: 3, borderSkipped: false }
        ]
      },
      options: {
        responsive: true, maintainAspectRatio: false,
        onClick: (_, els) => { if (els.length) { selectMonth(allMonths[els[0].index].key); showView('dash'); } },
        plugins: {
          legend: { display: true, position: 'top', labels: { color: d.text, font: { size: 10, family: MONO_FONT }, boxWidth: 10, boxHeight: 10, padding: 14 } },
          tooltip: { callbacks: { label: ctx => ' ' + ctx.dataset.label + ':' + fmtT(ctx.parsed.y) } }
        },
        scales: {
          x: { grid: { display: false }, ticks: d.tick, border: { display: false } },
          y: { grid: { color: d.grid }, ticks: d.tick, border: { display: false } }
        }
      }
    });
  }
}


// ══════════════════════════════════════════════════
// YEAR SUMMARY — Resumo anual
// ══════════════════════════════════════════════════
function renderYear() {
  const el = document.getElementById('yearContent');
  if (!el) return;
  if (!S.months.length) { el.innerHTML = '<div class="empty">nenhum mês cadastrado</div>'; return; }

  const years = [...new Set(S.months.map(m => m.year))].sort();
  const yearSub = document.getElementById('tbSub');
  let html = '';

  years.forEach(y => {
    const mths = S.months.filter(m => m.year === y);
    const totalAnual = mths.reduce((s, m) => s + monthTotal(m), 0);
    const incAnual = mths.reduce((s, m) => s + (S.incomes[m.key] || []).reduce((ss, i) => ss + i.amount, 0), 0);
    const saldoAnual = incAnual - totalAnual;

    // Categorias anuais
    const catAnual = {};
    mths.forEach(m => m.banks.forEach(b =>
      b.entries.filter(e => e.category).forEach(e => {
        catAnual[e.category] = (catAnual[e.category] || 0) + e.amount;
      })
    ));
    const topCats = Object.entries(catAnual).sort((a, b) => b[1] - a[1]).slice(0, 5);

    const monthH = Math.max(mths.length * 40 + 20, 60);
    const catH = Math.max(topCats.length * 38 + 20, 60);

    html += `
      <div class="yr-section">

        <!-- Cabeçalho do ano -->
        <div class="yr-header">
          <span class="yr-title">${y}</span>
          <div class="yr-stats">
            <span class="yr-stat">gastos
              <strong style="color:var(--text)">R$&nbsp;${fmt(totalAnual)}</strong>
            </span>
            <span class="yr-stat">entradas
              <strong style="color:var(--green)">R$&nbsp;${fmt(incAnual)}</strong>
            </span>
            <span class="yr-stat">saldo
              <strong style="color:${saldoAnual >= 0 ? 'var(--green)' : 'var(--red)'}">R$&nbsp;${fmt(saldoAnual)}</strong>
            </span>
          </div>
        </div>

        <!-- Entradas vs Gastos (apenas quando há 2+ meses) -->
        ${mths.length >= 2 ? `
          <div class="rep-card yr-card">
            <div class="rep-card-title">Entradas vs Gastos</div>
            <div style="position:relative;height:200px">
              <canvas id="yrBar_${y}"></canvas>
            </div>
          </div>
        ` : ''}

        <!-- Por Mês — Chart.js horizontal bar (clicável, substitui barras CSS) -->
        <div class="rep-card yr-card">
          <div class="rep-card-title">Por Mês</div>
          <div style="position:relative;height:${monthH}px">
            <canvas id="yrMonth_${y}"></canvas>
          </div>
        </div>

        <!-- Top Categorias -->
        <div class="rep-card yr-card">
          <div class="rep-card-title">Top Categorias</div>
          ${topCats.length ? `
            <div style="position:relative;height:${catH}px">
              <canvas id="yrCat_${y}"></canvas>
            </div>
          ` : `
            <div style="height:60px;display:flex;align-items:center;justify-content:center;
                 font-size:11px;color:var(--text3)">sem categorias registradas</div>
          `}
        </div>

      </div>`;
  });

  if (yearSub) yearSub.textContent = years.join(', ');
  el.innerHTML = html;

  // ── Charts ─────────────────────────────────────────────────────────────────
  const d = _chartDefaults();
  const fmtT = v => ' R$ ' + Number(v).toLocaleString('pt-BR', { minimumFractionDigits: 2 });

  years.forEach(y => {
    const mths = S.months.filter(m => m.year === y);

    // ── Entradas vs Gastos (grouped bar) ─────────────────────────────────
    if (mths.length >= 2) {
      _makeChart('yrBar_' + y, 'yrBar_' + y, {
        type: 'bar',
        data: {
          labels: mths.map(m => m.label.slice(0, 3)),
          datasets: [
            {
              label: 'Gastos',
              data: mths.map(m => monthTotal(m)),
              backgroundColor: '#4d9eff',
              borderRadius: 4,
              borderSkipped: false,
            },
            {
              label: 'Entradas',
              data: mths.map(m => (S.incomes[m.key] || []).reduce((s, i) => s + i.amount, 0)),
              backgroundColor: '#4ade80',
              borderRadius: 4,
              borderSkipped: false,
            }
          ]
        },
        options: {
          responsive: true,
          maintainAspectRatio: false,
          onClick: (_, els) => {
            if (els.length) { selectMonth(mths[els[0].index].key); showView('dash'); }
          },
          plugins: {
            legend: {
              display: true,
              position: 'top',
              labels: {
                color: d.text,
                font: { size: 10, family: MONO_FONT },
                boxWidth: 10,
                boxHeight: 10,
                padding: 14,
              }
            },
            tooltip: {
              callbacks: { label: ctx => ' ' + ctx.dataset.label + ':' + fmtT(ctx.parsed.y) }
            }
          },
          scales: {
            x: { grid: { display: false }, ticks: d.tick, border: { display: false } },
            y: { grid: { color: d.grid }, ticks: d.tick, border: { display: false } }
          }
        }
      });
    }

    // ── Por Mês (horizontal bar — clicável, com suporte a meta) ──────────
    const hasGoals = mths.some(m => m.goal);

    _makeChart('yrMonth_' + y, 'yrMonth_' + y, {
      type: 'bar',
      data: {
        labels: mths.map(m => m.label.slice(0, 3)),
        datasets: [
          {
            label: 'Gasto',
            data: mths.map(m => monthTotal(m)),
            // Vermelho quando passa da meta, azul normal
            backgroundColor: mths.map(m => {
              const tot = monthTotal(m);
              return (m.goal && tot > m.goal) ? '#ff4d4d88' : (getCSSVar('--accent') || '#4d9eff');
            }),
            borderRadius: 4,
            borderSkipped: false,
          },
          ...(hasGoals ? [{
            label: 'Meta',
            data: mths.map(m => m.goal || null),
            backgroundColor: 'rgba(255,255,255,0.05)',
            borderColor: 'rgba(255,255,255,0.10)',
            borderWidth: 1,
            borderRadius: 4,
            borderSkipped: false,
          }] : [])
        ]
      },
      options: {
        indexAxis: 'y',
        responsive: true,
        maintainAspectRatio: false,
        onClick: (_, els) => {
          if (els.length) { selectMonth(mths[els[0].index].key); showView('dash'); }
        },
        plugins: {
          legend: { display: false },
          tooltip: {
            callbacks: {
              label: ctx => {
                if (ctx.dataset.label === 'Meta') return ' Meta:' + fmtT(ctx.parsed.x);
                const m = mths[ctx.dataIndex];
                const tot = monthTotal(m);
                let str = fmtT(tot);
                if (m.goal) str += `  (${(tot / m.goal * 100).toFixed(0)}% da meta)`;
                return str;
              }
            }
          }
        },
        scales: {
          x: {
            grid: { color: d.grid },
            ticks: d.tick,
            border: { display: false },
          },
          y: {
            grid: { display: false },
            ticks: { ...d.tick, color: getCSSVar('--text2') || '#888' },
            border: { display: false },
          }
        }
      }
    });

    // ── Top Categorias ────────────────────────────────────────────────────
    const catAnual = {};
    mths.forEach(m => m.banks.forEach(b =>
      b.entries.filter(e => e.category).forEach(e => {
        catAnual[e.category] = (catAnual[e.category] || 0) + e.amount;
      })
    ));
    const topCats = Object.entries(catAnual).sort((a, b) => b[1] - a[1]).slice(0, 5);
    if (!topCats.length) return;

    _makeChart('yrCat_' + y, 'yrCat_' + y, {
      type: 'bar',
      data: {
        labels: topCats.map(([c]) => getCategoryIcon(c, c) + ' ' + c),
        datasets: [{
          data: topCats.map(([, v]) => v),
          backgroundColor: topCats.map((_, i) => CAT_COLORS[i % CAT_COLORS.length]),
          borderRadius: 4,
          borderSkipped: false,
        }]
      },
      options: {
        indexAxis: 'y',
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
          legend: { display: false },
          tooltip: { callbacks: { label: ctx => fmtT(ctx.parsed.x) } }
        },
        scales: {
          x: { grid: { color: d.grid }, ticks: d.tick, border: { display: false } },
          y: { grid: { display: false }, ticks: { ...d.tick, color: d.text }, border: { display: false } }
        }
      }
    });
  });
}

// renderHistory() em js/history.js

/* ── js/history.js ── */
// ══════════════════════════════════════════════════
// HISTORY.JS — Histórico de Pessoas entre Meses
// ══════════════════════════════════════════════════

function avatarColor(name) {
  let hash = 0;
  for (let i = 0; i < name.length; i++) {
    hash = name.charCodeAt(i) + ((hash << 5) - hash);
  }
  const hue = Math.abs(hash) % 360;
  return `hsl(${hue}, 55%, 48%)`;
}

function avatarInitials(name) {
  const parts = name.trim().split(/\s+/);
  return parts.length >= 2
    ? (parts[0][0] + parts[1][0]).toUpperCase()
    : name.trim().slice(0, 2).toUpperCase();
}

function toggleHistCard(header) {
  const detail = header.nextElementSibling;
  const chevron = header.querySelector('.hist-chevron');
  const isOpen = detail.style.display !== 'none';
  detail.style.display = isOpen ? 'none' : 'block';
  chevron.textContent = isOpen ? '▸' : '▾';
}

function renderHistory() {
  const el = document.getElementById('historyContent');
  if (!el) return;

  // ── Agrega dados por pessoa ──
  const pplAll = {};

  S.months.forEach(m => {
    m.banks.forEach(b => {
      // owner = 'other'
      b.entries.filter(e => e.owner === 'other' && e.person).forEach(e => {
        if (!pplAll[e.person]) pplAll[e.person] = { total: 0, months: {} };
        pplAll[e.person].total += e.amount;
        if (!pplAll[e.person].months[m.key]) pplAll[e.person].months[m.key] = { total: 0, items: [] };
        pplAll[e.person].months[m.key].total += e.amount;
        pplAll[e.person].months[m.key].items.push(e);
      });

      // owner = 'split'
      b.entries.filter(e => e.owner === 'split').forEach(e => {
        const people = (e.splitPeople || (e.person ? e.person.split(', ') : [])).filter(Boolean);
        if (!people.length) return;
        const count = e.splitCount || (people.length + 1);
        const myRatio = e.splitRatio ?? (1 / count);
        const share = e.amount * (1 - myRatio) / people.length;
        people.forEach(p => {
          if (!pplAll[p]) pplAll[p] = { total: 0, months: {} };
          pplAll[p].total += share;
          if (!pplAll[p].months[m.key]) pplAll[p].months[m.key] = { total: 0, items: [] };
          pplAll[p].months[m.key].total += share;
          pplAll[p].months[m.key].items.push({ ...e, desc: e.desc + ' (÷' + count + ')', amount: share });
        });
      });
    });
  });

  // ── Assinaturas de outras pessoas e em conjunto ──
  (S.subscriptions || []).filter(s => !s.endDate).forEach(s => {
    const owner = s.owner || 'mine';
    const monthlyAmt = s.cycle === 'mensal' ? s.amount : s.cycle === 'anual' ? s.amount / 12 : s.amount * 52 / 12;
    if (owner === 'other') {
      const person = (s.splitPeople || ['?'])[0];
      if (!pplAll[person]) pplAll[person] = { total: 0, months: {} };
      if (!pplAll[person].months['assinaturas']) pplAll[person].months['assinaturas'] = { total: 0, items: [] };
      pplAll[person].months['assinaturas'].total += monthlyAmt;
      pplAll[person].months['assinaturas'].items.push({ desc: s.name, amount: monthlyAmt, isSub: true });
      pplAll[person].total += monthlyAmt;
    } else if (owner === 'split') {
      const people = s.splitPeople || [];
      const count = people.length + 1;
      people.forEach((p, i) => {
        const perPerson = s.splitValues ? (s.splitValues[i] || 0) : monthlyAmt / count;
        if (!pplAll[p]) pplAll[p] = { total: 0, months: {} };
        if (!pplAll[p].months['assinaturas']) pplAll[p].months['assinaturas'] = { total: 0, items: [] };
        pplAll[p].months['assinaturas'].total += perPerson;
        pplAll[p].months['assinaturas'].items.push({ desc: s.name, amount: perPerson, isSub: true });
        pplAll[p].total += perPerson;
      });
    }
  });

  if (!Object.keys(pplAll).length) {
    el.innerHTML = '<div class="empty">nenhum lançamento de outras pessoas ainda</div>';
    return;
  }

  // ── Métricas gerais ──
  const totalGeral = Object.values(pplAll).reduce((s, d) => s + d.total, 0);
  const numPessoas = Object.keys(pplAll).length;
  const allMonthKeys = new Set();
  Object.values(pplAll).forEach(d =>
    Object.keys(d.months).forEach(k => k !== 'assinaturas' && allMonthKeys.add(k))
  );

  // ── Cards de resumo no topo ──
  const summaryHTML = `
    <div class="summary-grid" style="margin-bottom:24px">
      <div class="card">
        <div class="card-lbl">Total a Receber</div>
        <div class="card-val b">R$ ${fmt(totalGeral)}</div>
      </div>
      <div class="card">
        <div class="card-lbl">Pessoas Ativas</div>
        <div class="card-val">${numPessoas}</div>
      </div>
      <div class="card">
        <div class="card-lbl">Meses com Dados</div>
        <div class="card-val">${allMonthKeys.size}</div>
      </div>
    </div>`;

  // ── Card por pessoa ──
  const cardsHTML = Object.entries(pplAll)
    .sort((a, b) => b[1].total - a[1].total)
    .map(([name, data]) => {
      const pct = totalGeral > 0 ? (data.total / totalGeral * 100) : 0;
      const monthKeys = Object.keys(data.months).filter(k => k !== 'assinaturas');
      const monthCount = monthKeys.length;
      const avgPerMonth = monthCount > 0 ? data.total / monthCount : data.total;
      const color = avatarColor(name);
      const initials = avatarInitials(name);

      const rows = Object.entries(data.months)
        .sort((a, b) => {
          if (a[0] === 'assinaturas') return 1;
          if (b[0] === 'assinaturas') return -1;
          // Ordena pelos meses na ordem de S.months (mais recente primeiro)
          const ai = S.months.findIndex(m => m.key === a[0]);
          const bi = S.months.findIndex(m => m.key === b[0]);
          return bi - ai;
        })
        .map(([mk, md]) => `
          <tr>
            <td style="font-family:var(--mono);font-size:12px;white-space:nowrap">
              ${mk === 'assinaturas' ? '🔁 Assinaturas' : mk}
            </td>
            <td style="color:var(--text2);font-size:12px;max-width:0;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">
              ${md.items.map(i => i.isSub
                ? `${i.desc} <span class="bm bm-rec" style="font-size:9px">assinatura</span>`
                : i.desc).join(', ')}
            </td>
            <td style="white-space:nowrap">
              <span class="amt" style="color:var(--blue)">R$ ${fmt(md.total)}</span>
              ${mk === 'assinaturas' ? '<span style="font-size:10px;color:var(--text3);display:block">/mês</span>' : ''}
            </td>
          </tr>`).join('');

      return `
        <div class="tbl-block hist-card" style="margin-bottom:12px">
          <div class="tbl-head hist-card-header" onclick="toggleHistCard(this)" style="gap:12px;cursor:pointer;user-select:none">
            <div class="hist-avatar" style="background:${color}">${initials}</div>
            <div style="flex:1;min-width:0">
              <div style="font-weight:600;font-size:14px">${name}</div>
              <div style="font-size:11px;color:var(--text3);font-family:var(--mono)">
                R$ ${fmt(data.total)} · ${monthCount} mês${monthCount !== 1 ? 'es' : ''}
              </div>
            </div>
            <span class="tbl-total" style="color:var(--blue);flex-shrink:0">R$ ${fmt(data.total)}</span>
            <span class="hist-chevron">▸</span>
          </div>
          <div class="hist-detail" style="display:none">
            <div style="padding:10px 18px;border-bottom:1px solid var(--border)">
              <div style="display:flex;align-items:center;gap:10px">
                <div class="hist-progress-wrap">
                  <div class="hist-progress-fill" style="width:${Math.min(pct, 100).toFixed(1)}%"></div>
                </div>
                <span style="font-size:11px;font-family:var(--mono);color:var(--text2);white-space:nowrap">
                  ${pct.toFixed(1)}% do total
                </span>
              </div>
            </div>
            <table>
              <thead><tr><th>Mês</th><th>Itens</th><th>Total</th></tr></thead>
              <tbody>${rows}</tbody>
            </table>
            <div class="foot-row">
              <div class="foot-grp">
                <span class="foot-lbl">Total</span>
                <span class="foot-amt" style="color:var(--blue)">R$ ${fmt(data.total)}</span>
              </div>
              <div class="foot-grp">
                <span class="foot-lbl">Meses ativos</span>
                <span class="foot-amt">${monthCount}</span>
              </div>
              <div class="foot-grp">
                <span class="foot-lbl">Média/mês</span>
                <span class="foot-amt">R$ ${fmt(avgPerMonth)}</span>
              </div>
            </div>
          </div>
        </div>`;
    }).join('');

  el.innerHTML = summaryHTML + cardsHTML;
}

/* ── js/backup.js ── */
// ══════════════════════════════════════════════════
// BACKUP.JS — Export JSON, Import JSON, Export PDF
// ══════════════════════════════════════════════════

function openBackup() {
  openModal('mBackup');
}

function exportBackup() {
  const data = {
    months: S.months,
    pixEntries: S.pixEntries,
    recurrents: S.recurrents,
    incomes: S.incomes,
    subscriptions: S.subscriptions,
    installments: S.installments,
    exportedAt: new Date().toISOString(),
    version: '1.0'
  };
  const json = JSON.stringify(data, null, 2);
  const blob = new Blob([json], { type: 'application/json' });
  const a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = 'financas_backup_' + today() + '.json';
  a.click();
  URL.revokeObjectURL(a.href);
}

async function importBackup(input) {
  const file = input.files[0];
  if (!file) return;
  const r = new FileReader();
  r.onload = async e => {
    try {
      const d = JSON.parse(e.target.result);
      if (!d.months) { alert('Arquivo inválido — estrutura não reconhecida.'); return; }
      if (!confirm('Restaurar backup? Os dados atuais serão substituídos permanentemente.')) return;

      setSyncing(true);
      // Salva tudo no Supabase
      for (const m of (d.months || [])) {
        await dbSaveMonth(m);
        for (const b of (m.banks || [])) {
          await dbSaveBank(m.key, b);
          for (const entry of (b.entries || [])) {
            await dbSaveEntry(m.key, b.name, entry);
          }
        }
      }
      for (const [key, pxList] of Object.entries(d.pixEntries || {})) {
        for (const px of pxList) await dbSavePix(key, px);
      }
      for (const [key, recList] of Object.entries(d.recurrents || {})) {
        for (const r of recList) await dbSaveRecurrent(key, r);
      }
      for (const [key, incList] of Object.entries(d.incomes || {})) {
        for (const inc of incList) await dbSaveIncome(key, inc);
      }
      for (const sub of (d.subscriptions || [])) await dbSaveSub(sub);
      for (const inst of (d.installments || [])) await dbSaveInstallment(inst);

      setSyncing(false);
      alert('Backup restaurado com sucesso!');
      location.reload();
    } catch (err) {
      setSyncing(false);
      alert('Erro ao importar: ' + err.message);
    }
  };
  r.readAsText(file);
  // Limpa o input para permitir reimportar o mesmo arquivo
  input.value = '';
}

function exportMonthPDF() {
  const m = getMonth();
  if (!m) { alert('Selecione um mês.'); return; }

  const allE = m.banks.flatMap(b => b.entries.map(e => ({ ...e, bankName: b.name })));
  const pixL = S.pixEntries[m.key] || [];
  const recL = S.recurrents[m.key] || [];
  const incL = S.incomes[m.key] || [];

  const myT = allE.filter(e => e.owner === 'mine').reduce((s, e) => s + e.amount, 0);
  const othT = allE.filter(e => e.owner === 'other').reduce((s, e) => s + e.amount, 0);
  const pixT = pixL.reduce((s, p) => s + p.amount, 0);
  const recT = recL.reduce((s, r) => s + r.amount, 0);
  const incT = incL.reduce((s, i) => s + i.amount, 0);
  const saldo = incT - (myT + pixT + recT);

  const pplMap = {};
  allE.filter(e => e.owner === 'other').forEach(e => {
    if (!pplMap[e.person]) pplMap[e.person] = 0;
    pplMap[e.person] += e.amount;
  });

  const w = window.open('', '_blank');
  w.document.write(`<!DOCTYPE html>
<html lang="pt-BR">
<head>
  <meta charset="UTF-8">
  <title>Finanças ${m.label} ${m.year}</title>
  <style>
    body { font-family: Arial, sans-serif; font-size: 13px; color: #1a1a1a; padding: 32px; max-width: 900px; margin: 0 auto; }
    h1 { font-size: 22px; margin-bottom: 4px; }
    h2 { font-size: 14px; margin: 24px 0 8px; border-bottom: 2px solid #eee; padding-bottom: 4px; color: #333; }
    p { color: #666; font-size: 12px; margin-bottom: 16px; }
    table { width: 100%; border-collapse: collapse; margin-bottom: 16px; }
    th { background: #f5f5f5; padding: 7px 10px; text-align: left; font-size: 11px; border: 1px solid #ddd; text-transform: uppercase; letter-spacing: 1px; }
    td { padding: 7px 10px; border: 1px solid #eee; font-size: 12px; }
    tr:nth-child(even) td { background: #fafafa; }
    .total { text-align: right; font-weight: bold; }
    .grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 12px; margin-bottom: 20px; }
    .card { background: #f9f9f9; border: 1px solid #eee; border-radius: 6px; padding: 14px; }
    .card-lbl { font-size: 10px; color: #999; text-transform: uppercase; letter-spacing: 1px; margin-bottom: 4px; }
    .card-val { font-size: 20px; font-weight: bold; }
    .badge-mine { background: #e8f4ff; color: #2563eb; padding: 2px 6px; border-radius: 4px; font-size: 11px; }
    .badge-other { background: #f3f0ff; color: #7c3aed; padding: 2px 6px; border-radius: 4px; font-size: 11px; }
    @media print { body { padding: 16px; } .no-print { display: none; } }
  </style>
</head>
<body>
  <h1>Finanças — ${m.label} ${m.year}</h1>
  <p>Gerado em ${new Date().toLocaleDateString('pt-BR', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</p>

  <div class="grid">
    <div class="card"><div class="card-lbl">Total Gastos</div><div class="card-val">R$ ${fmt(myT + othT + pixT + recT)}</div></div>
    <div class="card"><div class="card-lbl">Entradas</div><div class="card-val" style="color:#16a34a">R$ ${fmt(incT)}</div></div>
    <div class="card"><div class="card-lbl">Saldo</div><div class="card-val" style="color:${saldo >= 0 ? '#16a34a' : '#dc2626'}">R$ ${fmt(saldo)}</div></div>
    <div class="card"><div class="card-lbl">Meus Gastos</div><div class="card-val" style="color:#2563eb">R$ ${fmt(myT + pixT + recT)}</div></div>
    <div class="card"><div class="card-lbl">A Receber</div><div class="card-val" style="color:#7c3aed">R$ ${fmt(othT)}</div></div>
    ${m.goal ? `<div class="card"><div class="card-lbl">Meta</div><div class="card-val" style="color:${myT + othT + pixT + recT > m.goal ? '#dc2626' : '#16a34a'}">${((myT + othT + pixT + recT) / m.goal * 100).toFixed(0)}%</div></div>` : ''}
  </div>

  ${m.banks.map(b => `
    <h2>${b.name}</h2>
    <table>
      <tr><th>Descrição</th><th>De quem</th><th>Categoria</th><th>Tipo</th><th>Data</th><th>Valor</th></tr>
      ${b.entries.map(e => `
        <tr>
          <td>${e.desc}${e.installTotal ? ` (${e.installCurrent}/${e.installTotal})` : ''}</td>
          <td>${e.owner === 'other' ? `<span class="badge-other">${e.person}</span>` : '<span class="badge-mine">Meu</span>'}</td>
          <td>${e.category || '—'}</td>
          <td>${e.type === 'installment' ? 'Parcelado' : e.type === 'pix' ? 'Pix' : 'Normal'}</td>
          <td>${fmtDate(e.date)}</td>
          <td class="total">R$ ${fmt(e.amount)}</td>
        </tr>`).join('')}
      <tr style="background:#f0f0f0;font-weight:bold">
        <td colspan="5">Total ${b.name}</td>
        <td class="total">R$ ${fmt(b.entries.reduce((s, e) => s + e.amount, 0))}</td>
      </tr>
    </table>`).join('')}

  ${pixL.length ? `
    <h2>Pix Enviados</h2>
    <table>
      <tr><th>Para</th><th>Banco</th><th>Motivo</th><th>Data</th><th>Valor</th></tr>
      ${pixL.map(p => `<tr><td>${p.to}</td><td>${p.bank || '—'}</td><td>${p.obs || '—'}</td><td>${fmtDate(p.date)}</td><td class="total">R$ ${fmt(p.amount)}</td></tr>`).join('')}
    </table>` : ''}

  ${recL.length ? `
    <h2>Contas Fixas</h2>
    <table>
      <tr><th>Descrição</th><th>Vencimento</th><th>Observação</th><th>Valor</th></tr>
      ${recL.map(r => `<tr><td>${r.desc}</td><td>Dia ${r.day || '—'}</td><td>${r.obs || '—'}</td><td class="total">R$ ${fmt(r.amount)}</td></tr>`).join('')}
    </table>` : ''}

  ${incL.length ? `
    <h2>Entradas</h2>
    <table>
      <tr><th>Descrição</th><th>Tipo</th><th>De quem</th><th>Data</th><th>Valor</th></tr>
      ${incL.map(i => `<tr><td>${i.desc}</td><td>${i.incType || '—'}</td><td>${i.owner === 'other' ? i.person : 'Meu'}</td><td>${fmtDate(i.date)}</td><td class="total" style="color:#16a34a">R$ ${fmt(i.amount)}</td></tr>`).join('')}
    </table>` : ''}

  ${Object.keys(pplMap).length ? `
    <h2>Resumo — A Receber</h2>
    <table>
      <tr><th>Pessoa</th><th>Total a Receber</th></tr>
      ${Object.entries(pplMap).sort((a, b) => b[1] - a[1]).map(([n, t]) => `<tr><td>${n}</td><td class="total" style="color:#7c3aed">R$ ${fmt(t)}</td></tr>`).join('')}
    </table>` : ''}

  <script>window.print();<\/script>
</body>
</html>`);
  w.document.close();
}

/* ── js/ai-engine.js ── */
// ══════════════════════════════════════════════════
// AI-ENGINE.JS — Importação de Extratos (parser local)
// ══════════════════════════════════════════════════

function openAI() {
  if (!S.months.length) { alert('Crie um mês primeiro.'); return; }
  const ms = document.getElementById('aiMonthSel');
  ms.innerHTML = S.months.map(m => `<option value="${m.key}">${m.label} ${m.year}</option>`).join('');
  ms.value = S.currentMonth || S.months[0].key;
  updateAIBankSel();
  document.getElementById('aiText').value = '';
  document.getElementById('aiResult').style.display = 'none';
  document.getElementById('aiBaseActions').style.display = 'flex';
  document.getElementById('aiBtnText').textContent = '✨ Interpretar com IA';
  S.aiParsed = [];
  openModal('mAI');
}

function updateAIBankSel() {
  const key = document.getElementById('aiMonthSel').value;
  const m = S.months.find(x => x.key === key);
  const bs = document.getElementById('aiBankSel');
  if (m && m.banks.length) {
    bs.innerHTML = m.banks.map(b => `<option>${b.name}</option>`).join('');
  } else {
    bs.innerHTML = '<option value="">-- banco será criado --</option>';
  }
}


async function runAI() {
  const text = document.getElementById('aiText').value.trim();
  if (!text) { alert('Cole o texto do extrato.'); return; }

  document.getElementById('aiBtnText').innerHTML = '<span class="spinner"></span>Interpretando...';
  document.getElementById('aiBaseActions').style.display = 'none';

  setTimeout(() => {
    try {
      S.aiParsed = parseExtrato(text);
      renderAIEntries();
    } catch (e) {
      alert('Erro ao interpretar o texto.');
      document.getElementById('aiBtnText').textContent = '✨ Interpretar com IA';
      document.getElementById('aiBaseActions').style.display = 'flex';
    }
  }, 300);
}
function parseExtrato(raw) {
  const entries = [];
  const lines = raw.split('\n').map(l => l.trim()).filter(l => l.length);
  const supMap = { '¹': 1, '²': 2, '³': 3, '⁴': 4, '⁵': 5, '⁶': 6, '⁷': 7, '⁸': 8, '⁹': 9 };
  const pKw = ['sogra', 'sogro', 'mãe', 'mae', 'pai', 'namorado', 'namorada',
    'irmã', 'irmao', 'irmão', 'amigo', 'amiga', 'marido', 'esposa', 'tia', 'tio', 'vó', 'vo'];
  let curPerson = null;

  for (const line of lines) {
    // "eu: 55+25" ou "Sogra: 13+44"
    const blk = line.match(/^([a-zA-ZÀ-ú\s]{1,30}?)\s*:\s*(.*)/i);
    if (blk) {
      const nm = blk[1].trim();
      const rest = blk[2].trim();
      const isMe = /^eu$/i.test(nm);
      curPerson = isMe ? null : nm;
      if (rest) {
        const nums = rest.match(/[\d]+(?:[.,][\d]+)?/g) || [];
        nums.forEach(n => {
          const a = parseFloat(n.replace(',', '.'));
          if (a > 0 && a < 100000) entries.push({
            desc: curPerson || 'Lançamento', amount: a,
            owner: curPerson ? 'other' : 'mine', person: curPerson,
            installment: false, installCurrent: null, installTotal: null
          });
        });
      }
      continue;
    }

    // "Moto 195¹°" — parcelado com superscript
    const instSup = line.match(/^(.+?)\s+([\d]+(?:[.,][\d]+)?)\s*([¹²³⁴⁵⁶⁷⁸⁹])°?/);
    if (instSup) {
      const a = parseFloat(instSup[2].replace(',', '.'));
      if (a > 0) entries.push({
        desc: instSup[1].trim(), amount: a,
        owner: curPerson ? 'other' : 'mine', person: curPerson,
        installment: true, installCurrent: supMap[instSup[3]] || 1, installTotal: 12
      });
      continue;
    }

    // "Notebook 195 1/12" — parcelado com fração
    const instFrac = line.match(/^(.+?)\s+([\d]+(?:[.,][\d]+)?)\s+(\d+)\/(\d+)/);
    if (instFrac) {
      const a = parseFloat(instFrac[2].replace(',', '.'));
      if (a > 0) entries.push({
        desc: instFrac[1].trim(), amount: a,
        owner: curPerson ? 'other' : 'mine', person: curPerson,
        installment: true, installCurrent: parseInt(instFrac[3]), installTotal: parseInt(instFrac[4])
      });
      continue;
    }

    // "iFood 32,00" — padrão
    const std = line.match(/^(.+?)\s+([\d]+[.,][\d]{2})$/)
      || line.match(/^([\d]+[.,][\d]{2})\s+(.+)$/);
    if (std) {
      let desc, amtStr;
      if (/^[\d]/.test(std[1])) { amtStr = std[1]; desc = std[2]; }
      else { desc = std[1]; amtStr = std[2]; }
      const a = parseFloat(amtStr.replace(',', '.'));
      const isOth = pKw.some(k => desc.toLowerCase().includes(k));
      if (a > 0 && a < 100000) entries.push({
        desc: desc.trim(), amount: a,
        owner: isOth ? 'other' : 'mine',
        person: isOth ? desc.trim() : curPerson,
        installment: false, installCurrent: null, installTotal: null
      });
    }
  }
  return entries.filter(e => e.amount > 0);
}

function renderAIEntries() {
  document.getElementById('aiBtnText').textContent = '✨ Interpretar novamente';
  document.getElementById('aiBaseActions').style.display = 'none';

  if (!S.aiParsed.length) {
    document.getElementById('aiResult').style.display = 'block';
    document.getElementById('aiEntryList').innerHTML =
      '<div style="color:var(--text3);font-family:var(--mono);font-size:12px;padding:10px">Nenhum lançamento identificado. Tente reformatar o texto.</div>';
    return;
  }

  document.getElementById('aiEntryList').innerHTML = S.aiParsed.map((e, i) => `
    <div class="ai-entry-item">
      <input type="checkbox" id="aic${i}" checked>
      <div style="flex:1;min-width:0">
        <div style="font-size:13px;font-weight:500">${e.desc}
          ${e.person ? `→ <span style="color:var(--blue)">${e.person}</span>` : ''}
        </div>
        <div style="font-size:11px;color:var(--text3);font-family:var(--mono)">
          ${e.installment ? `parcela ${e.installCurrent || 1}/${e.installTotal || '?'} · ` : ''}
          <span style="color:var(--accent)">R$ ${fmt(e.amount)}</span>
          · ${e.owner === 'mine' ? 'meu' : 'outro'}
        </div>
      </div>
      <input type="number" value="${e.amount}" step="0.01" min="0"
        style="padding:4px 6px;font-size:11px;width:80px;text-align:right;background:var(--bg3);border:1px solid var(--border2);border-radius:4px;color:var(--text)"
        onchange="S.aiParsed[${i}].amount = parseFloat(this.value) || 0">
    </div>`).join('');

  document.getElementById('aiResult').style.display = 'block';
}

async function importAIEntries() {
  const monthKey = document.getElementById('aiMonthSel').value;
  const bankName = document.getElementById('aiBankSel').value || 'Importado';
  const m = S.months.find(x => x.key === monthKey);
  if (!m) { alert('Mês não encontrado.'); return; }

  let bank = m.banks.find(b => b.name === bankName);
  if (!bank) {
    const newBank = { name: bankName, color: 'azure', entries: [] };
    m.banks.push(newBank);
    await dbSaveBank(monthKey, newBank);
    bank = m.banks[m.banks.length - 1];
  }

  setSyncing(true);
  for (let i = 0; i < S.aiParsed.length; i++) {
    const e = S.aiParsed[i];
    if (!document.getElementById('aic' + i)?.checked) continue;
    if (e.amount <= 0) continue;

    if (e.installment && e.installTotal > 1) {
      const gId = 'grp_ai_' + Date.now() + '_' + i;
      const entry = {
        id: Date.now() + i, desc: e.desc, amount: e.amount, date: today(),
        owner: e.owner, person: e.person || null, category: null, note: null,
        type: 'installment', installCurrent: e.installCurrent || 1,
        installTotal: e.installTotal, groupId: gId
      };
      bank.entries.push(entry);
      await dbSaveEntry(monthKey, bankName, entry);
      await registerFutureInst({
        desc: e.desc, partAmt: e.amount, total: e.installTotal,
        cur: e.installCurrent || 1, bankName, owner: e.owner,
        person: e.person || null, cat: null, gId,
        startKey: monthKey, date: today()
      });
    } else {
      const entry = {
        id: Date.now() + i, desc: e.desc, amount: e.amount, date: today(),
        owner: e.owner, person: e.person || null,
        category: null, note: null, type: 'normal'
      };
      bank.entries.push(entry);
      await dbSaveEntry(monthKey, bankName, entry);
    }
  }
  setSyncing(false);

  S.currentMonth = monthKey;
  S.currentBank = bankName;
  save();
  renderMonthList();
  selectMonth(monthKey);
  closeModal('mAI');
}

